/* ===================== QUESTION BANK ===================== */
const QUESTIONS = [
  {"id":"A1","domain":"ALG","skill":"linear-equations","diff":1,"type":"mental","format":"mc","stem":"If 3x + 7 = 22, what is the value of x?","choices":["3","5","7","15"],"answer":1,"solution":"3x + 7 = 22 → 3x = 15 → x = 5.","shortcut":"Subtract 7 (→15), divide by 3. Do it in your head.","desmos":"Type y=3x+7-22 and read the x-intercept (x=5), but this is faster by hand."},
  {"id":"A2","domain":"ALG","skill":"linear-equations","diff":1,"type":"mental","format":"grid","stem":"If 5(x − 2) = 20, what is the value of x?","answer":"6","solution":"Divide by 5: x − 2 = 4 → x = 6.","shortcut":"Divide both sides by 5 first to kill the parentheses.","desmos":"y=5(x-2)-20, x-intercept at 6."},
  {"id":"A3","domain":"ALG","skill":"linear-functions","diff":2,"type":"work","format":"mc","stem":"A line has slope 2 and passes through (0, 3). What is y when x = 4?","choices":["8","9","11","14"],"answer":2,"solution":"y = 2x + 3. At x=4: y = 8 + 3 = 11.","shortcut":"Start at 3, add slope×Δx = 2×4 = 8 → 11.","desmos":"Graph y=2x+3, trace to x=4."},
  {"id":"A4","domain":"ALG","skill":"systems","diff":2,"type":"desmos","format":"mc","stem":"What is the x-coordinate of the solution to the system y = 2x + 1 and y = −x + 7 ?","choices":["1","2","3","5"],"answer":1,"solution":"2x + 1 = −x + 7 → 3x = 6 → x = 2 (y = 5).","shortcut":"Set equal, collect x's: 3x=6.","desmos":"Type both lines, click the intersection → (2, 5)."},
  {"id":"A5","domain":"ALG","skill":"inequalities","diff":2,"type":"mental","format":"mc","stem":"If 2x − 3 > 7, what is the smallest integer value of x?","choices":["4","5","6","7"],"answer":2,"solution":"2x > 10 → x > 5. Smallest integer greater than 5 is 6.","shortcut":"Solve like an equation, then take the next integer past the boundary.","desmos":"Graph y=2x-3 and y=7; region where the line is higher starts past x=5."},
  {"id":"A6","domain":"ALG","skill":"slope","diff":3,"type":"work","format":"grid","stem":"A line passes through the points (2, 5) and (6, 17). What is its slope?","answer":"3","solution":"slope = (17 − 5)/(6 − 2) = 12/4 = 3.","shortcut":"Δy/Δx = 12/4 = 3.","desmos":"Plot both points, add a segment; or type the slope formula."},
  {"id":"A7","domain":"ALG","skill":"linear-equations","diff":3,"type":"work","format":"mc","stem":"In the equation 3x − 2y = 12, what is x when y = 3?","choices":["2","4","6","9"],"answer":2,"solution":"3x − 2(3) = 12 → 3x − 6 = 12 → 3x = 18 → x = 6.","shortcut":"Plug y=3, solve the one-variable equation.","desmos":"Graph 3x-2y=12 and y=3, click intersection."},
  {"id":"A8","domain":"ALG","skill":"linear-functions","diff":3,"type":"desmos","format":"mc","stem":"For what value of c does the line 4x + cy = 8 have a slope of −2?","choices":["1","2","4","8"],"answer":1,"solution":"Solve for y: cy = −4x + 8 → y = (−4/c)x + 8/c. Slope = −4/c = −2 → c = 2.","shortcut":"Slope of Ax+By=C is −A/B. Set −4/c = −2 → c=2.","desmos":"Add slider c, type 4x+cy=8, drag c until the line's slope looks like −2."},
  {"id":"A9","domain":"ALG","skill":"systems","diff":4,"type":"work","format":"grid","stem":"The system kx + 3y = 6 and 4x + 6y = 12 has infinitely many solutions. What is k?","answer":"2","solution":"Infinitely many ⇒ same line. Divide the 2nd by 2: 2x + 3y = 6. Match the 1st: k = 2.","shortcut":"Make the two equations identical (proportional). 4→2, 6→3, 12→6, so k=2.","desmos":"Add slider k; graph both. When they overlap completely, k=2."},
  {"id":"A10","domain":"ALG","skill":"absolute-value","diff":4,"type":"desmos","format":"grid","stem":"What is the sum of all solutions to |2x − 5| = 9 ?","answer":"5","solution":"2x−5 = 9 → x = 7; 2x−5 = −9 → x = −2. Sum = 7 + (−2) = 5.","shortcut":"Two cases: ±9. The two solutions are symmetric about 2.5, so sum = 2(2.5)=5.","desmos":"Graph y=|2x-5| and y=9; the two intersections are x=7 and x=-2."},
  {"id":"B1","domain":"ADV","skill":"quadratics","diff":2,"type":"mental","format":"mc","stem":"If x² = 49 and x > 0, what is x?","choices":["±7","7","24.5","49"],"answer":1,"solution":"x = ±7, but x > 0, so x = 7.","shortcut":"√49 = 7; the constraint picks the positive root.","desmos":"Graph y=x²-49; positive x-intercept is 7."},
  {"id":"B2","domain":"ADV","skill":"factoring","diff":2,"type":"work","format":"mc","stem":"Which value is a solution to (x + 3)(x − 5) = 0 ?","choices":["−5","3","5","8"],"answer":2,"solution":"Zero-product: x = −3 or x = 5. Among the choices, 5.","shortcut":"Solutions are the values that make each factor 0: −3 and 5.","desmos":"Graph y=(x+3)(x-5); x-intercepts at −3 and 5."},
  {"id":"B3","domain":"ADV","skill":"quadratics","diff":3,"type":"desmos","format":"grid","stem":"What is the larger solution to x² − 5x + 6 = 0 ?","answer":"3","solution":"Factor: (x−2)(x−3)=0 → x = 2 or 3. Larger is 3.","shortcut":"Two numbers multiplying to 6, adding to 5: 2 and 3.","desmos":"Graph y=x²-5x+6; x-intercepts at 2 and 3."},
  {"id":"B4","domain":"ADV","skill":"functions","diff":3,"type":"work","format":"grid","stem":"If f(x) = 2x² − 3x + 1, what is f(2)?","answer":"3","solution":"f(2) = 2(4) − 3(2) + 1 = 8 − 6 + 1 = 3.","shortcut":"Square first (4), then 2·4=8, minus 6, plus 1.","desmos":"Define f(x)=2x^2-3x+1, then type f(2)."},
  {"id":"B5","domain":"ADV","skill":"vertex-form","diff":3,"type":"work","format":"mc","stem":"The graph of y = (x − 3)² − 4 is a parabola. What is the x-coordinate of its vertex?","choices":["−4","−3","3","4"],"answer":2,"solution":"Vertex form y=(x−h)²+k has vertex (h,k). Here h=3, k=−4, so x=3.","shortcut":"Flip the sign inside the parentheses: (x−3) → vertex x=3.","desmos":"Graph it, click the lowest point → (3, −4)."},
  {"id":"B6","domain":"ADV","skill":"quadratics","diff":4,"type":"desmos","format":"grid","stem":"What is the sum of the solutions to x² + 6x + 5 = 0 ?","answer":"-6","solution":"Roots −1 and −5 (factor (x+1)(x+5)). Sum = −6. (Also −b/a = −6.)","shortcut":"Sum of roots = −b/a = −6/1 = −6. Instant, no factoring.","desmos":"Graph; x-intercepts at −1 and −5, sum −6."},
  {"id":"B7","domain":"ADV","skill":"exponents","diff":4,"type":"work","format":"mc","stem":"If 2ˣ = 32, what is x?","choices":["4","5","6","16"],"answer":1,"solution":"32 = 2⁵, so x = 5.","shortcut":"Count powers of 2: 2,4,8,16,32 → fifth power.","desmos":"Graph y=2^x and y=32, intersection at x=5."},
  {"id":"B8","domain":"ADV","skill":"exponential-models","diff":4,"type":"desmos","format":"mc","stem":"A population is modeled by P = 200(1.05)ᵗ, where t is in years. By what percent does it grow each year?","choices":["1.05%","5%","20%","105%"],"answer":1,"solution":"Growth factor 1.05 = 1 + 0.05, so 5% per year.","shortcut":"Base − 1 = growth rate. 1.05 → 5%.","desmos":"Graph it; each year the value multiplies by 1.05 (5% more)."},
  {"id":"B9","domain":"ADV","skill":"discriminant","diff":5,"type":"work","format":"grid","stem":"The equation x² + bx + 9 = 0 has exactly one real solution, and b > 0. What is b?","answer":"6","solution":"One solution ⇒ discriminant 0: b² − 4(1)(9) = 0 → b² = 36 → b = 6 (b>0).","shortcut":"Perfect square: x²+bx+9=(x+3)² needs b=6.","desmos":"Add slider b; graph y=x²+bx+9; find b where it just touches the x-axis."},
  {"id":"B10","domain":"ADV","skill":"discriminant","diff":5,"type":"desmos","format":"mc","stem":"How many real solutions does x² = 2x − 5 have?","choices":["0","1","2","Infinitely many"],"answer":0,"solution":"x² − 2x + 5 = 0; discriminant = 4 − 20 = −16 < 0 → no real solutions.","shortcut":"Discriminant negative ⇒ 0 real solutions. No need to solve.","desmos":"Graph y=x² and y=2x−5; they never intersect → 0 solutions."},
  {"id":"C1","domain":"PSD","skill":"percent","diff":1,"type":"mental","format":"mc","stem":"What is 20% of 150?","choices":["20","30","45","75"],"answer":1,"solution":"0.20 × 150 = 30.","shortcut":"10% of 150 is 15; double it → 30.","desmos":"Type 0.2*150."},
  {"id":"C2","domain":"PSD","skill":"rates","diff":2,"type":"work","format":"mc","stem":"A car travels 180 miles in 3 hours at a constant speed. What is its speed in miles per hour?","choices":["45","54","60","90"],"answer":2,"solution":"180 / 3 = 60 mph.","shortcut":"Distance ÷ time.","desmos":"Type 180/3."},
  {"id":"C3","domain":"PSD","skill":"ratios","diff":2,"type":"mental","format":"mc","stem":"Two quantities are in the ratio 3 : 5 and total 40. What is the larger quantity?","choices":["15","20","24","25"],"answer":3,"solution":"3+5 = 8 parts; 40/8 = 5 per part; larger = 5×5 = 25.","shortcut":"Total ÷ (sum of ratio parts) = value per part, then ×5.","desmos":"Type 40/8*5."},
  {"id":"C4","domain":"PSD","skill":"percent","diff":3,"type":"work","format":"grid","stem":"A $40 shirt is marked down 25%. What is the sale price, in dollars?","answer":"30","solution":"25% of 40 = 10; 40 − 10 = 30. (Or 40 × 0.75 = 30.)","shortcut":"Down 25% = keep 75% = ×0.75.","desmos":"Type 40*0.75."},
  {"id":"C5","domain":"PSD","skill":"statistics","diff":3,"type":"work","format":"grid","stem":"The mean of the four numbers 4, 8, 10, and x is 8. What is x?","answer":"10","solution":"Sum must be 4×8 = 32. 4+8+10 = 22, so x = 10.","shortcut":"Mean × count = total; subtract the knowns.","desmos":"Solve: mean([4,8,10,x]) — or set 22+x=32."},
  {"id":"C6","domain":"PSD","skill":"percent-change","diff":4,"type":"work","format":"mc","stem":"A quantity increases from 50 to 65. What is the percent increase?","choices":["15%","23%","30%","65%"],"answer":2,"solution":"Increase = 15; 15/50 = 0.30 = 30%.","shortcut":"Change ÷ original. 15/50 = 30%.","desmos":"Type (65-50)/50*100."},
  {"id":"C7","domain":"PSD","skill":"proportions","diff":4,"type":"work","format":"grid","stem":"A recipe uses 2 cups of flour for every 3 eggs. How many cups of flour are needed for 9 eggs?","answer":"6","solution":"9 eggs is 3× the 3 eggs, so flour is 3 × 2 = 6 cups.","shortcut":"9/3 = 3 batches; 2×3 = 6.","desmos":"Type 2*(9/3)."},
  {"id":"C8","domain":"PSD","skill":"probability","diff":4,"type":"work","format":"mc","stem":"A bag has 3 red, 5 blue, and 2 green marbles. If one is drawn at random, what is the probability it is red?","choices":["1/10","3/10","3/7","1/3"],"answer":1,"solution":"Total = 10; P(red) = 3/10.","shortcut":"Favorable ÷ total = 3/10.","desmos":"Type 3/10 = 0.3."},
  {"id":"C9","domain":"PSD","skill":"statistics","diff":4,"type":"desmos","format":"grid","stem":"What is the median of 2, 5, 7, 7, 9, and 12 ?","answer":"7","solution":"Six values; median = average of 3rd and 4th = (7+7)/2 = 7.","shortcut":"Even count → average the two middle numbers.","desmos":"Type median([2,5,7,7,9,12])."},
  {"id":"C10","domain":"PSD","skill":"data-models","diff":5,"type":"desmos","format":"mc","stem":"A line of best fit for some data is y = 3.2x + 12. The model predicts the value at x = 25 is closest to which?","choices":["80","92","100","112"],"answer":1,"solution":"y = 3.2(25) + 12 = 80 + 12 = 92.","shortcut":"3.2×25 = 80, +12 = 92.","desmos":"Type 3.2*25+12, or graph the line and trace to x=25."},
  {"id":"D1","domain":"GEO","skill":"angles","diff":1,"type":"mental","format":"mc","stem":"Two angles of a triangle measure 50° and 60°. What is the third angle?","choices":["60°","70°","80°","110°"],"answer":1,"solution":"Angles sum to 180°: 180 − 50 − 60 = 70°.","shortcut":"180 minus the two given.","desmos":""},
  {"id":"D2","domain":"GEO","skill":"area","diff":2,"type":"mental","format":"mc","stem":"A rectangle has length 8 and width 5. What is its area?","choices":["13","26","40","45"],"answer":2,"solution":"Area = 8 × 5 = 40.","shortcut":"length × width.","desmos":""},
  {"id":"D3","domain":"GEO","skill":"circles","diff":2,"type":"mental","format":"mc","stem":"A circle has radius 3. What is its area?","choices":["3π","6π","9π","12π"],"answer":2,"solution":"Area = πr² = π(3²) = 9π.","shortcut":"Square the radius, times π.","desmos":"Type pi*3^2 for the decimal."},
  {"id":"D4","domain":"GEO","skill":"pythagorean","diff":3,"type":"work","format":"grid","stem":"A right triangle has legs of length 6 and 8. What is the length of the hypotenuse?","answer":"10","solution":"√(6² + 8²) = √(36+64) = √100 = 10.","shortcut":"Recognize the 6-8-10 (3-4-5 ×2) triple.","desmos":"Type sqrt(6^2+8^2)."},
  {"id":"D5","domain":"GEO","skill":"circles","diff":3,"type":"work","format":"mc","stem":"A circle has circumference 10π. What is its radius?","choices":["5","10","20","25"],"answer":0,"solution":"C = 2πr → 10π = 2πr → r = 5.","shortcut":"Divide circumference by 2π.","desmos":""},
  {"id":"D6","domain":"GEO","skill":"similar-triangles","diff":3,"type":"work","format":"mc","stem":"Two triangles are similar. One has sides 3 and 4; the corresponding sides of the other are 6 and x. What is x?","choices":["5","7","8","12"],"answer":2,"solution":"Scale factor 6/3 = 2, so x = 4 × 2 = 8.","shortcut":"Find the scale factor, multiply.","desmos":"Solve 3/4 = 6/x → x=8."},
  {"id":"D7","domain":"GEO","skill":"coordinate","diff":4,"type":"desmos","format":"mc","stem":"What is the distance between the points (1, 2) and (4, 6)?","choices":["3","4","5","7"],"answer":2,"solution":"√((4−1)² + (6−2)²) = √(9+16) = √25 = 5.","shortcut":"3-4-5 triangle again.","desmos":"Plot both points, draw a segment, or type sqrt(3^2+4^2)."},
  {"id":"D8","domain":"GEO","skill":"trig","diff":4,"type":"work","format":"grid","stem":"In a right triangle, the hypotenuse is 10 and one angle is 30°. What is the length of the side opposite the 30° angle?","answer":"5","solution":"opposite = hypotenuse × sin(30°) = 10 × 0.5 = 5.","shortcut":"sin30°=1/2, so opposite is half the hypotenuse.","desmos":"Type 10*sin(30) — set Desmos to degrees, or 10*sin(pi/6)."},
  {"id":"D9","domain":"GEO","skill":"volume","diff":4,"type":"work","format":"mc","stem":"A cylinder has radius 3 and height 5. What is its volume?","choices":["15π","30π","45π","75π"],"answer":2,"solution":"V = πr²h = π(9)(5) = 45π.","shortcut":"Area of base (9π) × height (5).","desmos":"Type pi*3^2*5."},
  {"id":"D10","domain":"GEO","skill":"arc-sector","diff":5,"type":"work","format":"mc","stem":"In a circle of radius 6, a central angle of 60° cuts off an arc. What is the arc's length?","choices":["π","2π","6π","12π"],"answer":1,"solution":"Arc = (60/360)(2π·6) = (1/6)(12π) = 2π.","shortcut":"Fraction of circle (60/360 = 1/6) × circumference (12π).","desmos":"Type (60/360)*2*pi*6."},
  {"id":"A11","domain":"ALG","skill":"linear-equations","diff":1,"type":"mental","format":"mc","stem":"If 3x + 7 = 22, what is the value of x?","choices":["3","5","7","15"],"answer":1,"solution":"Subtract 7 from both sides: 3x = 15. Divide by 3: x = 5.","shortcut":"22 − 7 = 15, then 15 ÷ 3 = 5.","desmos":"Type 3x+7=22 on one line; Desmos solves to x=5."},
  {"id":"A12","domain":"ALG","skill":"linear-equations","diff":1,"type":"mental","format":"grid","stem":"If 5(x − 2) = 35, what is the value of x?","answer":"9","solution":"Divide both sides by 5: x − 2 = 7. Add 2: x = 9.","shortcut":"35 ÷ 5 = 7, then 7 + 2 = 9.","desmos":"Enter 5(x-2)=35; read x=9."},
  {"id":"A13","domain":"ALG","skill":"slope","diff":1,"type":"mental","format":"mc","stem":"What is the slope of the line that passes through the points (1, 2) and (4, 11)?","choices":["1/3","3","9","13"],"answer":1,"solution":"Slope = (11 − 2) / (4 − 1) = 9 / 3 = 3.","shortcut":"Rise 9 over run 3 equals 3.","desmos":"Plot both points and the line y=3x-1; slope is 3. Or compute (11-2)/(4-1)."},
  {"id":"A14","domain":"ALG","skill":"linear-functions","diff":2,"type":"mental","format":"mc","stem":"The function f is defined by f(x) = 2x − 9. What is the value of f(6)?","choices":["−3","3","12","21"],"answer":1,"solution":"Substitute x = 6: f(6) = 2(6) − 9 = 12 − 9 = 3.","shortcut":"Double 6 is 12, minus 9 is 3.","desmos":"Define f(x)=2x-9, then type f(6) to get 3."},
  {"id":"A15","domain":"ALG","skill":"inequalities","diff":2,"type":"mental","format":"mc","stem":"Which of the following is a solution to the inequality −2x + 3 &gt; 11?","choices":["x = −5","x = −4","x = 0","x = 4"],"answer":0,"solution":"Subtract 3: −2x &gt; 8. Divide by −2 and flip the sign: x &lt; −4. Only x = −5 satisfies x &lt; −4.","shortcut":"Solve to x &lt; −4; the only choice less than −4 is −5.","desmos":"Graph y=-2x+3 and y=11; the inequality holds where the line is above 11, i.e. x&lt;-4."},
  {"id":"A16","domain":"ALG","skill":"linear-word-problems","diff":2,"type":"work","format":"mc","stem":"A taxi charges a flat fee of $3.50 plus $2.25 per mile. Which equation gives the total cost C, in dollars, of a ride of m miles?","choices":["C = 3.50m + 2.25","C = 2.25m + 3.50","C = 5.75m","C = 2.25(m + 3.50)"],"answer":1,"solution":"The per-mile rate 2.25 multiplies the number of miles m, and the flat fee 3.50 is added once: C = 2.25m + 3.50.","shortcut":"Rate times miles plus the one-time fee.","desmos":"Not needed; this is a model-building question."},
  {"id":"A17","domain":"ALG","skill":"systems","diff":2,"type":"work","format":"grid","stem":"If x + y = 10 and x − y = 4, what is the value of x?","answer":"7","solution":"Add the equations: 2x = 14, so x = 7.","shortcut":"Adding eliminates y: 10 + 4 = 14, half is 7.","desmos":"Type x+y=10 and x-y=4; the intersection is (7,3), so x=7."},
  {"id":"A18","domain":"ALG","skill":"linear-equations","diff":2,"type":"work","format":"mc","stem":"If 4(x + 3) − 2x = 26, what is the value of x?","choices":["4","7","10","19"],"answer":1,"solution":"Distribute: 4x + 12 − 2x = 26, so 2x + 12 = 26. Subtract 12: 2x = 14. Divide: x = 7.","shortcut":"Combine to 2x + 12 = 26; (26−12)/2 = 7.","desmos":"Enter 4(x+3)-2x=26; read x=7."},
  {"id":"A19","domain":"ALG","skill":"linear-functions","diff":2,"type":"work","format":"mc","stem":"A line in the xy-plane has a y-intercept of −4 and passes through the point (3, 5). What is the equation of the line?","choices":["y = 3x − 4","y = 3x + 4","y = (1/3)x − 4","y = −3x − 4"],"answer":0,"solution":"The y-intercept is −4, so b = −4. Slope = (5 − (−4)) / (3 − 0) = 9/3 = 3. So y = 3x − 4.","shortcut":"From (0,−4) to (3,5): rise 9, run 3, slope 3, intercept −4.","desmos":"Plot (3,5) and (0,-4), fit y=3x-4 and confirm both points lie on it."},
  {"id":"A20","domain":"ALG","skill":"absolute-value","diff":2,"type":"work","format":"mc","stem":"If |2x − 5| = 9, what is the sum of all possible values of x?","choices":["2","5","7","9"],"answer":1,"solution":"2x − 5 = 9 gives x = 7. 2x − 5 = −9 gives 2x = −4, x = −2. Sum = 7 + (−2) = 5.","shortcut":"The two solutions are symmetric about x = 5/2; their sum is 2(5/2) = 5.","desmos":"Graph y=|2x-5| and y=9; intersections at x=-2 and x=7, summing to 5."},
  {"id":"A21","domain":"ALG","skill":"linear-equations","diff":3,"type":"work","format":"grid","stem":"If (2x)/3 + x/2 = 7, what is the value of x?","answer":"6","solution":"Multiply through by the LCD 6: 6·(2x/3) + 6·(x/2) = 6·7, giving 4x + 3x = 42. So 7x = 42 and x = 6.","shortcut":"Combine: 2x/3 + x/2 = 7x/6 = 7, so x = 6.","desmos":"Enter (2x)/3 + x/2 = 7; read x = 6."},
  {"id":"A22","domain":"ALG","skill":"slope","diff":3,"type":"work","format":"mc","stem":"Line ℓ passes through (−2, 7) and is perpendicular to the line 4x + 2y = 9. What is the slope of line ℓ?","choices":["−2","−1/2","1/2","2"],"answer":2,"solution":"Rewrite 4x + 2y = 9 as y = −2x + 9/2, slope −2. Perpendicular slope is the negative reciprocal: 1/2.","shortcut":"Given line slope −2; perpendicular slope is +1/2.","desmos":"Graph 4x+2y=9 to see slope -2; perpendicular slope is 1/2."},
  {"id":"A23","domain":"ALG","skill":"systems","diff":3,"type":"work","format":"mc","stem":"What is the solution (x, y) to the system 3x + 2y = 16 and 5x − 2y = 8?","choices":["(3, 3.5)","(2, 5)","(3, 7/2)","(4, 2)"],"answer":0,"solution":"Add the equations: 8x = 24, so x = 3. Substitute: 3(3) + 2y = 16, 2y = 7, y = 3.5. Solution (3, 3.5).","shortcut":"The +2y and −2y cancel: 8x = 24, x = 3; then y = 3.5.","desmos":"Graph both lines; intersection at (3, 3.5)."},
  {"id":"A24","domain":"ALG","skill":"inequalities","diff":3,"type":"work","format":"mc","stem":"If 3(2x − 1) ≤ 5x + 4, what is the greatest integer value of x that satisfies the inequality?","choices":["6","7","8","9"],"answer":1,"solution":"Expand: 6x − 3 ≤ 5x + 4. Subtract 5x: x − 3 ≤ 4. Add 3: x ≤ 7. The greatest integer is 7.","shortcut":"Collect x on one side: x ≤ 7; greatest integer is 7.","desmos":"Graph y=3(2x-1) and y=5x+4; first line is below or equal up to x=7."},
  {"id":"A25","domain":"ALG","skill":"linear-word-problems","diff":3,"type":"work","format":"grid","stem":"A water tank starts with 50 gallons and is drained at a constant rate of 3.5 gallons per minute. After how many minutes will the tank contain 8 gallons?","answer":"12","solution":"Volume V = 50 − 3.5t. Set 50 − 3.5t = 8: 3.5t = 42, t = 12 minutes.","shortcut":"It must lose 42 gallons; 42 ÷ 3.5 = 12.","desmos":"Graph y=50-3.5x and y=8; intersection at x=12."},
  {"id":"A26","domain":"ALG","skill":"linear-functions","diff":3,"type":"work","format":"mc","stem":"The linear function g satisfies g(2) = 11 and g(6) = 23. What is g(0)?","choices":["3","5","8","9"],"answer":1,"solution":"Slope = (23 − 11)/(6 − 2) = 12/4 = 3. Using g(2) = 11: g(x) = 3x + b, 11 = 6 + b, b = 5. So g(0) = 5.","shortcut":"Slope 3; back up from g(2)=11 by 2 steps of 3: 11 − 6 = 5.","desmos":"Plot (2,11) and (6,23), fit y=3x+5; the y-intercept g(0)=5."},
  {"id":"A27","domain":"ALG","skill":"absolute-value","diff":3,"type":"work","format":"mc","stem":"Which of the following describes all solutions to |x − 3| &lt; 5?","choices":["x &lt; 8","−2 &lt; x &lt; 8","x &lt; −2 or x &gt; 8","−8 &lt; x &lt; 2"],"answer":1,"solution":"|x − 3| &lt; 5 means −5 &lt; x − 3 &lt; 5. Add 3 to all parts: −2 &lt; x &lt; 8.","shortcut":"Center 3, radius 5: interval (3−5, 3+5) = (−2, 8).","desmos":"Graph y=|x-3| and y=5; the curve is below 5 between x=-2 and x=8."},
  {"id":"A28","domain":"ALG","skill":"linear-equations","diff":3,"type":"work","format":"grid","stem":"If 0.2(x + 5) = 0.5x − 1.4, what is the value of x?","answer":"8","solution":"Multiply by 10: 2(x + 5) = 5x − 14. Expand: 2x + 10 = 5x − 14. So 24 = 3x, x = 8.","shortcut":"Clear decimals (×10), then 2x + 10 = 5x − 14 gives 3x = 24, x = 8.","desmos":"Enter 0.2(x+5)=0.5x-1.4; read x=8."},
  {"id":"A29","domain":"ALG","skill":"linear-word-problems","diff":3,"type":"work","format":"mc","stem":"A gym membership costs $25 to join plus a monthly fee. After 8 months, a member has paid $185 total. What is the monthly fee, in dollars?","choices":["18","20","23","26.25"],"answer":1,"solution":"Let f be the monthly fee. 25 + 8f = 185, so 8f = 160, f = 20.","shortcut":"Subtract the join fee: 185 − 25 = 160; 160 ÷ 8 = 20.","desmos":"Solve 25+8f=185 for f=20."},
  {"id":"A30","domain":"ALG","skill":"systems","diff":3,"type":"work","format":"grid","stem":"At a concession stand, 2 hot dogs and 3 drinks cost $13, while 4 hot dogs and 1 drink cost $16. What is the price, in dollars, of one drink?","answer":"2","solution":"Let h, d be prices. 2h + 3d = 13 and 4h + d = 16. From the second, d = 16 − 4h. Substitute: 2h + 3(16 − 4h) = 13, so 2h + 48 − 12h = 13, −10h = −35, h = 3.5. Then d = 16 − 4(3.5) = 16 − 14 = 2. Check first equation: 2(3.5) + 3(2) = 7 + 6 = 13 ✓. The drink costs $2.","shortcut":"Solve the second for d, substitute; h = 3.5, d = 2.","desmos":"Graph 2h+3d=13 and 4h+d=16 (use x for h, y for d); intersection (3.5, 2), drink = 2."},
  {"id":"A31","domain":"ALG","skill":"systems","diff":4,"type":"work","format":"mc","stem":"For what value of k does the system 2x + 3y = 7 and 6x + ky = 5 have no solution?","choices":["2","6","9","21"],"answer":2,"solution":"No solution requires parallel, non-identical lines: the coefficient ratios match but the constant ratio differs. 6/2 = 3, so k/3 = 3 gives k = 9. Check constants: 5/7 ≠ 3, so truly no solution. k = 9.","shortcut":"Make the second equation a multiple of the first in x,y: multiply first by 3 → 6x + 9y, so k = 9.","desmos":"Graph 2x+3y=7 and 6x+9y=5; the lines are parallel (no intersection) when k=9."},
  {"id":"A32","domain":"ALG","skill":"systems","diff":4,"type":"work","format":"grid","stem":"The system cx + 4y = 10 and 3x + 2y = 5 has infinitely many solutions. What is the value of c?","answer":"6","solution":"Infinitely many solutions means the equations are proportional. First equation must be a multiple of the second. Multiply 3x + 2y = 5 by 2: 6x + 4y = 10, which matches cx + 4y = 10 when c = 6 (and constants 10 match).","shortcut":"Double the second equation to match the 4y and the 10; that forces c = 6.","desmos":"Graph both; with c=6 they are the same line (infinite solutions)."},
  {"id":"A33","domain":"ALG","skill":"linear-functions","diff":4,"type":"work","format":"mc","stem":"A line is defined by f(x) = mx + b. If f(−1) = 4 and f(3) = −8, what is the value of m + b?","choices":["−4","−3","1","−2"],"answer":3,"solution":"Slope m = (−8 − 4)/(3 − (−1)) = −12/4 = −3. Using f(−1) = 4: 4 = −3(−1) + b = 3 + b, so b = 1. Then m + b = −3 + 1 = −2.","shortcut":"m = −3, b = 1, sum = −2.","desmos":"Plot (-1,4) and (3,-8), fit y=-3x+1; m+b = -3+1 = -2."},
  {"id":"A34","domain":"ALG","skill":"inequalities","diff":4,"type":"work","format":"mc","stem":"A student needs an average of at least 90 on four tests to earn an A. The first three scores are 85, 92, and 88. What is the minimum score s on the fourth test that earns an A?","choices":["90","93","95","97"],"answer":2,"solution":"(85 + 92 + 88 + s)/4 ≥ 90, so 265 + s ≥ 360, s ≥ 95. The minimum is 95.","shortcut":"Total needed is 360; current total 265; need 95 more.","desmos":"Solve (265+s)/4 ≥ 90 → s ≥ 95."},
  {"id":"A35","domain":"ALG","skill":"absolute-value","diff":4,"type":"work","format":"mc","stem":"A machine fills bottles to a target of 500 mL. A bottle passes inspection only if its volume v satisfies |v − 500| ≤ 12. Which volume (in mL) would FAIL inspection?","choices":["489","495","511","513"],"answer":3,"solution":"Passing means 488 ≤ v ≤ 512. 513 lies outside this range (|513 − 500| = 13 &gt; 12), so it fails.","shortcut":"Acceptable range is 500 ± 12 = [488, 512]; 513 is just outside.","desmos":"Graph y=|x-500| and y=12; values where the curve exceeds 12 fail (e.g., 513)."},
  {"id":"A36","domain":"ALG","skill":"linear-word-problems","diff":4,"type":"work","format":"grid","stem":"A printing company charges a one-time setup fee plus a fixed cost per flyer. An order of 200 flyers costs $90, and an order of 500 flyers costs $180. What is the cost, in dollars, of an order of 350 flyers?","answer":"135","solution":"Cost-per-flyer = (180 − 90)/(500 − 200) = 90/300 = 0.30. Setup fee: 90 = setup + 0.30(200) = setup + 60, so setup = 30. For 350 flyers: 30 + 0.30(350) = 30 + 105 = 135.","shortcut":"350 is the midpoint of 200 and 500, so the cost is the average: (90 + 180)/2 = 135.","desmos":"Plot (200,90) and (500,180), fit y=0.3x+30, evaluate at x=350 to get 135."},
  {"id":"A37","domain":"ALG","skill":"linear-functions","diff":4,"type":"work","format":"mc","stem":"The cost C, in dollars, to produce x units is C = 4.5x + 1200. Which statement best interprets the number 4.5 in this context?","choices":["The fixed cost is $4.50.","Each additional unit increases the cost by $4.50.","It costs $4.50 to produce 1200 units.","The cost is $4.50 when no units are produced."],"answer":1,"solution":"In C = 4.5x + 1200, the coefficient of x (the slope) is the rate of change: each additional unit adds $4.50 to the cost. The 1200 is the fixed cost.","shortcut":"Slope = cost per unit; 4.5 = $4.50 added per unit.","desmos":"Not needed; interpretation question."},
  {"id":"A38","domain":"ALG","skill":"systems","diff":4,"type":"work","format":"grid","stem":"A 40-liter mixture is 25% acid. How many liters of pure acid must be added so that the new mixture is 40% acid?","answer":"10","solution":"Initial acid = 0.25(40) = 10 L. Let a be liters of pure acid added. New acid = 10 + a, new total = 40 + a. Set (10 + a)/(40 + a) = 0.40: 10 + a = 16 + 0.4a, 0.6a = 6, a = 10.","shortcut":"Set up acid balance: 10 + a = 0.4(40 + a); solve a = 10.","desmos":"Graph y=(10+x)/(40+x) and y=0.4; intersection at x=10."},
  {"id":"A39","domain":"ALG","skill":"inequalities","diff":4,"type":"work","format":"mc","stem":"A delivery van can carry at most 1,500 kg. It is loaded with x boxes weighing 18 kg each and y crates weighing 45 kg each. Which inequality represents the loads the van can carry?","choices":["18x + 45y ≥ 1500","18x + 45y ≤ 1500","45x + 18y ≤ 1500","18x + 45y &lt; 1500"],"answer":1,"solution":"Total weight is 18x + 45y. \"At most\" 1,500 kg means the total is less than or equal to 1,500: 18x + 45y ≤ 1500.","shortcut":"\"At most\" → ≤; weights times counts summed ≤ 1500.","desmos":"Graph 18x+45y≤1500 to see the feasible region."},
  {"id":"A40","domain":"ALG","skill":"slope","diff":4,"type":"work","format":"grid","stem":"Line ℓ passes through the points (a, 5) and (7, 13) and has a slope of 4. What is the value of a?","answer":"5","solution":"Slope = (13 − 5)/(7 − a) = 8/(7 − a) = 4. So 7 − a = 2, a = 5.","shortcut":"8 divided by (7 − a) = 4 means 7 − a = 2, so a = 5.","desmos":"Graph the line y=4(x-7)+13 and find where y=5: x=5."},
  {"id":"A41","domain":"ALG","skill":"linear-equations","diff":4,"type":"work","format":"mc","stem":"If 3(2x − a) = 6x − 15 for all values of x, what is the value of a?","choices":["3","5","−5","15"],"answer":1,"solution":"Expand the left side: 6x − 3a. For this to equal 6x − 15 for all x, the constant terms must match: −3a = −15, so a = 5.","shortcut":"−3a = −15 → a = 5.","desmos":"Not needed; identity-coefficient matching."},
  {"id":"A42","domain":"ALG","skill":"systems","diff":5,"type":"work","format":"mc","stem":"The system of equations y = (1/2)x + 3 and y = (1/2)x + c has exactly one solution when which condition holds?","choices":["c = 3","c ≠ 3","c = −3","There is no such value of c."],"answer":3,"solution":"Both lines have slope 1/2. If c = 3 the lines are identical (infinitely many solutions); if c ≠ 3 they are parallel and distinct (no solution). They can never have exactly one solution, so no value of c works.","shortcut":"Equal slopes → never exactly one solution; the answer is that no such c exists.","desmos":"Graph both with a slider for c; the lines are always parallel, never crossing exactly once."},
  {"id":"A43","domain":"ALG","skill":"linear-word-problems","diff":5,"type":"work","format":"grid","stem":"Two trains leave the same station traveling in opposite directions. The first travels at 60 mph and the second at 75 mph. The second train leaves 1 hour after the first. How many hours after the FIRST train departs are the trains 600 miles apart?","answer":"5","solution":"Let t be hours after the first train leaves. First train distance: 60t. Second train travels (t − 1) hours: 75(t − 1). Total: 60t + 75(t − 1) = 600. So 60t + 75t − 75 = 600, 135t = 675, t = 5.","shortcut":"60t + 75(t−1) = 600 → 135t = 675 → t = 5.","desmos":"Graph y=60x+75(x-1) and y=600; intersection at x=5."},
  {"id":"A44","domain":"ALG","skill":"absolute-value","diff":5,"type":"work","format":"grid","stem":"If |3x − 7| = |x + 5|, what is the sum of all possible values of x?","answer":"6.5","solution":"Case 1: 3x − 7 = x + 5 → 2x = 12 → x = 6. Case 2: 3x − 7 = −(x + 5) → 3x − 7 = −x − 5 → 4x = 2 → x = 1/2. Sum = 6 + 1/2 = 6.5.","shortcut":"Solve both sign cases: x = 6 and x = 1/2; sum 6.5.","desmos":"Graph y=|3x-7| and y=|x+5|; intersections at x=0.5 and x=6, sum 6.5."},
  {"id":"A45","domain":"ALG","skill":"inequalities","diff":5,"type":"work","format":"mc","stem":"A system is defined by y &gt; 2x − 1 and y ≤ −x + 5. Which point lies in the solution region of BOTH inequalities?","choices":["(3, 2)","(0, 6)","(1, 3)","(4, 0)"],"answer":2,"solution":"Test (1, 3): y &gt; 2x − 1 → 3 &gt; 1 ✓; y ≤ −x + 5 → 3 ≤ 4 ✓. Both hold. (3,2): 2 &gt; 5 ✗. (0,6): 6 ≤ 5 ✗. (4,0): 0 &gt; 7 ✗.","shortcut":"Quick-test each point in both inequalities; only (1,3) passes both.","desmos":"Graph y&gt;2x-1 and y≤-x+5; (1,3) is in the overlapping shaded region."},
  {"id":"A46","domain":"ALG","skill":"systems","diff":5,"type":"work","format":"grid","stem":"In the system kx − 6y = 18 and 2x + 3y = 5, the lines are perpendicular. What is the value of k? Give your answer as a decimal or fraction.","answer":"9","solution":"Slope of first: kx − 6y = 18 → y = (k/6)x − 3, slope k/6. Slope of second: 2x + 3y = 5 → y = (−2/3)x + 5/3, slope −2/3. Perpendicular means slopes multiply to −1: (k/6)(−2/3) = −1 → −2k/18 = −1 → −k/9 = −1 → k = 9.","shortcut":"(k/6)(−2/3) = −1 → k = 9.","desmos":"Graph both with a slider for k; the lines meet at right angles when k=9."},
  {"id":"A47","domain":"ALG","skill":"linear-functions","diff":5,"type":"work","format":"mc","stem":"The function h is linear, and h(x + 2) = h(x) + 6 for all x. If h(1) = 4, what is h(7)?","choices":["16","19","22","25"],"answer":2,"solution":"h(x + 2) − h(x) = 6 means the function increases 6 over each step of 2, so the slope is 3. h(x) = 3x + b; h(1) = 3 + b = 4, b = 1, so h(x) = 3x + 1. h(7) = 21 + 1 = 22.","shortcut":"Slope = 6/2 = 3; from h(1)=4, add 3 per unit: h(7)=4+3·6=22.","desmos":"Define h(x)=3x+1, check h(1)=4, evaluate h(7)=22."},
  {"id":"A48","domain":"ALG","skill":"linear-word-problems","diff":5,"type":"work","format":"grid","stem":"Alex invests a total of $10,000 in two accounts. Account A earns 4% simple annual interest and Account B earns 7% simple annual interest. After one year, the total interest earned is $580. How many dollars were invested in Account A?","answer":"4000","solution":"Let A be the amount in Account A; then 10000 − A is in B. Interest: 0.04A + 0.07(10000 − A) = 580. So 0.04A + 700 − 0.07A = 580, −0.03A = −120, A = 4000.","shortcut":"0.04A + 0.07(10000−A)=580 → −0.03A = −120 → A = 4000.","desmos":"Graph y=0.04x+0.07(10000-x) and y=580; intersection at x=4000."},
  {"id":"A49","domain":"ALG","skill":"slope","diff":5,"type":"work","format":"mc","stem":"The line y = mx + 4 passes through the point (6, 1). What is the value of m?","choices":["−2","−1/2","1/2","2"],"answer":1,"solution":"Substitute the point (6, 1): 1 = 6m + 4, so 6m = −3, m = −1/2.","shortcut":"Plug (6,1) into y = mx + 4: 1 = 6m + 4 → m = −1/2.","desmos":"Graph y=mx+4 with a slider; set it through (6,1) to find m=-1/2."},
  {"id":"A50","domain":"ALG","skill":"linear-equations","diff":5,"type":"work","format":"grid","stem":"The equation 7x + 12 = 7x + b is true for infinitely many values of x. What is the value of b?","answer":"12","solution":"Subtract 7x from both sides: 12 = b. This is an identity (true for all x) only when b = 12; for any other b the equation has no solution. So b = 12.","shortcut":"Equal x-coefficients: solvability depends on constants; 12 = b only when b = 12.","desmos":"Graph y=7x+12 and y=7x+b with a slider; they coincide only when b=12."},
  {"id":"B11","domain":"ADV","skill":"quadratics","diff":1,"type":"mental","format":"mc","stem":"What are the solutions to x² &minus; 9 = 0?","choices":["x = 3 only","x = &minus;3 only","x = 3 and x = &minus;3","x = 9 and x = &minus;9"],"answer":2,"solution":"x² = 9, so x = ±3. A difference of squares: (x&minus;3)(x+3)=0.","shortcut":"Difference of squares gives ±√9 = ±3.","desmos":"Graph y=x²&minus;9; x-intercepts at &minus;3 and 3."},
  {"id":"B12","domain":"ADV","skill":"exponents","diff":1,"type":"mental","format":"mc","stem":"Simplify (2x³)² .","choices":["2x⁶","4x⁵","4x⁶","2x⁵"],"answer":2,"solution":"(2x³)² = 2²·x^(3·2) = 4x⁶.","shortcut":"Square the coefficient, multiply the exponent.","desmos":""},
  {"id":"B13","domain":"ADV","skill":"vertex-form","diff":2,"type":"mental","format":"mc","stem":"The function f(x) = (x &minus; 4)² + 3 has its minimum value at which point?","choices":["(4, 3)","(&minus;4, 3)","(4, &minus;3)","(3, 4)"],"answer":0,"solution":"Vertex form (x&minus;h)²+k has vertex (h,k) = (4,3); since the leading coefficient is positive, this is the minimum.","shortcut":"Flip the sign inside; keep the sign of k: (4,3).","desmos":"Graph and read the vertex."},
  {"id":"B14","domain":"ADV","skill":"factoring","diff":2,"type":"mental","format":"mc","stem":"Which is a factor of x² + 5x + 6?","choices":["x + 1","x + 2","x + 5","x &minus; 3"],"answer":1,"solution":"x²+5x+6 = (x+2)(x+3). So x+2 is a factor.","shortcut":"Find two numbers multiplying to 6, adding to 5: 2 and 3.","desmos":""},
  {"id":"B15","domain":"ADV","skill":"functions","diff":2,"type":"mental","format":"grid","stem":"If f(x) = 3x² &minus; 2x + 1, what is f(2)?","answer":"9","solution":"f(2) = 3(4) &minus; 2(2) + 1 = 12 &minus; 4 + 1 = 9.","shortcut":"Plug in carefully: 12&minus;4+1=9.","desmos":""},
  {"id":"B16","domain":"ADV","skill":"exponential-models","diff":2,"type":"work","format":"mc","stem":"A population of bacteria doubles every 3 hours. If it starts at 500, which models the population P after t hours?","choices":["P = 500(2)^(t/3)","P = 500(2)^(3t)","P = 500(3)^(t/2)","P = 500 + 2(t/3)"],"answer":0,"solution":"Doubling means base 2; the exponent is the number of doubling periods, t/3.","shortcut":"Base = growth factor (2); exponent = t ÷ period (3).","desmos":""},
  {"id":"B17","domain":"ADV","skill":"quadratics","diff":3,"type":"work","format":"mc","stem":"If the sum of the roots of x² &minus; 7x + k = 0 is 7 and the product is 12, what is k?","choices":["7","12","&minus;12","&minus;7"],"answer":1,"solution":"For x²+bx+c, sum of roots = &minus;b = 7 (consistent) and product = c = k. Product is 12, so k = 12.","shortcut":"Product of roots = constant term c = k = 12.","desmos":""},
  {"id":"B18","domain":"ADV","skill":"discriminant","diff":3,"type":"work","format":"mc","stem":"For what value of c does x² + 6x + c = 0 have exactly one real solution?","choices":["3","6","9","36"],"answer":2,"solution":"One solution requires discriminant b²&minus;4ac = 0: 36 &minus; 4c = 0, so c = 9.","shortcut":"Set 36 = 4c → c = 9 (perfect square trinomial).","desmos":"Slide c until the parabola is tangent to the x-axis."},
  {"id":"B19","domain":"ADV","skill":"nonlinear-systems","diff":3,"type":"work","format":"mc","stem":"The system y = x² and y = x + 6 has two solutions. What is the sum of the x-coordinates of the solutions?","choices":["&minus;1","1","5","6"],"answer":1,"solution":"x² = x + 6 → x² &minus; x &minus; 6 = 0. Sum of roots = &minus;(&minus;1)/1 = 1.","shortcut":"Sum of roots = &minus;b/a = 1.","desmos":"Graph both; x-intercepts of intersections are &minus;2 and 3, sum 1."},
  {"id":"B20","domain":"ADV","skill":"rational-equations","diff":3,"type":"work","format":"grid","stem":"Solve for x: 2/(x &minus; 1) = 4. ","answer":"3/2","solution":"2 = 4(x&minus;1) → 2 = 4x &minus; 4 → 4x = 6 → x = 3/2.","shortcut":"Cross-multiply: 2 = 4(x&minus;1).","desmos":"Graph y=2/(x&minus;1) and y=4; intersect at x=1.5."},
  {"id":"B21","domain":"ADV","skill":"radicals","diff":3,"type":"work","format":"mc","stem":"Solve for x: √(2x + 3) = 5.","choices":["1","8","11","14"],"answer":2,"solution":"Square both sides: 2x + 3 = 25 → 2x = 22 → x = 11. Check: √25 = 5. ✓","shortcut":"Square: 2x+3=25.","desmos":""},
  {"id":"B22","domain":"ADV","skill":"polynomials","diff":3,"type":"work","format":"mc","stem":"If P(x) = x³ &minus; 4x² + x + 6 and P(3) = 0, which is a factor of P(x)?","choices":["x + 3","x &minus; 3","x &minus; 6","x + 2"],"answer":1,"solution":"By the Factor Theorem, P(3)=0 means (x&minus;3) is a factor.","shortcut":"Root r → factor (x&minus;r). r=3 → (x&minus;3).","desmos":""},
  {"id":"B23","domain":"ADV","skill":"function-transformations","diff":3,"type":"work","format":"mc","stem":"The graph of y = f(x) is shifted right 2 units and up 5 units. Which represents the new graph?","choices":["y = f(x + 2) + 5","y = f(x &minus; 2) + 5","y = f(x &minus; 2) &minus; 5","y = f(x + 2) &minus; 5"],"answer":1,"solution":"Right by 2 replaces x with (x&minus;2); up by 5 adds 5 outside: y = f(x&minus;2)+5.","shortcut":"Horizontal shifts are 'opposite'; vertical shifts match sign.","desmos":""},
  {"id":"B24","domain":"ADV","skill":"quadratics","diff":4,"type":"work","format":"mc","stem":"The quadratic f(x) = 2x² &minus; 12x + 23 is written in vertex form a(x&minus;h)²+k. What is the value of k?","choices":["&minus;13","5","11","23"],"answer":1,"solution":"2(x²&minus;6x)+23 = 2(x²&minus;6x+9&minus;9)+23 = 2(x&minus;3)²&minus;18+23 = 2(x&minus;3)²+5. So k=5.","shortcut":"Vertex x = &minus;b/2a = 3; k = f(3) = 18&minus;36+23 = 5.","desmos":"Graph and read the y-value of the vertex."},
  {"id":"B25","domain":"ADV","skill":"discriminant","diff":4,"type":"work","format":"mc","stem":"For which values of k does kx² + 4x + 1 = 0 have two distinct real solutions? (k ≠ 0)","choices":["k &lt; 4","k &gt; 4","k &lt; 4 and k ≠ 0","k &gt; &minus;4"],"answer":2,"solution":"Two distinct real roots need b²&minus;4ac &gt; 0: 16 &minus; 4k &gt; 0 → k &lt; 4. Also k ≠ 0 for it to be quadratic.","shortcut":"16 &gt; 4k → k &lt; 4, excluding k=0.","desmos":"Slide k; parabola crosses x-axis twice when k&lt;4."},
  {"id":"B26","domain":"ADV","skill":"exponential-models","diff":4,"type":"work","format":"mc","stem":"A radioactive sample has a half-life of 8 days. If 80 grams remain after 24 days, how many grams were present initially?","choices":["160","240","320","640"],"answer":3,"solution":"24 days = 3 half-lives, so the amount has been halved 3 times: factor (1/2)³ = 1/8. Initial = 80 × 8 = 640 grams.","shortcut":"3 half-lives → multiply remaining by 2³ = 8.","desmos":""},
  {"id":"B27","domain":"ADV","skill":"nonlinear-systems","diff":4,"type":"desmos","format":"grid","stem":"The line y = 2x + c is tangent to the parabola y = x² + 3. What is the value of c?","answer":"2","solution":"Set x²+3 = 2x+c → x² &minus; 2x + (3&minus;c) = 0. Tangent means discriminant 0: 4 &minus; 4(3&minus;c) = 0 → 1 = 3&minus;c → c = 2.","shortcut":"Tangent ⇒ discriminant = 0.","desmos":"Add slider c; slide until the line just touches the parabola at c=2."},
  {"id":"B28","domain":"ADV","skill":"polynomials","diff":4,"type":"work","format":"mc","stem":"The polynomial p(x) = x³ &minus; 2x² &minus; 5x + 6 has roots that include x = 1. What is the sum of the other two roots?","choices":["1","&minus;1","2","5"],"answer":0,"solution":"Sum of all three roots = &minus;(&minus;2)/1 = 2. One root is 1, so the other two sum to 2 &minus; 1 = 1.","shortcut":"Sum of all roots = &minus;b/a = 2; subtract the known root.","desmos":"Graph p(x); roots are 1, 3, &minus;2; other two sum to 1."},
  {"id":"B29","domain":"ADV","skill":"rational-equations","diff":4,"type":"work","format":"mc","stem":"Solve for x (x &gt; 0): x + 6/x = 5. What is the sum of all solutions?","choices":["1","5","6","11"],"answer":1,"solution":"Multiply by x: x² + 6 = 5x → x² &minus; 5x + 6 = 0 → (x&minus;2)(x&minus;3)=0 → x = 2 or 3. Both positive and valid. Sum = 2 + 3 = 5.","shortcut":"Clear denominator → quadratic; sum of roots = &minus;b/a = 5.","desmos":"Graph y=x+6/x and y=5; intersections at x=2 and x=3."},
  {"id":"B30","domain":"ADV","skill":"radicals","diff":4,"type":"work","format":"grid","stem":"Solve for x: x &minus; √(x + 2) = 4 (give the valid solution).","answer":"7","solution":"√(x+2) = x&minus;4. Square: x+2 = x²&minus;8x+16 → x²&minus;9x+14=0 → (x&minus;7)(x&minus;2)=0. x=2 gives √4=2 ≠ 2&minus;4=&minus;2 (reject). x=7: √9=3 = 7&minus;4 ✓.","shortcut":"Isolate radical, square, then check for extraneous roots.","desmos":"Graph y=x&minus;√(x+2) and y=4; intersection at x=7."},
  {"id":"B31","domain":"ADV","skill":"function-transformations","diff":4,"type":"work","format":"mc","stem":"If g(x) = f(2x), how does the graph of g compare to f?","choices":["Horizontal stretch by factor 2","Horizontal compression by factor 1/2","Vertical stretch by factor 2","Shift left 2"],"answer":1,"solution":"Replacing x with 2x compresses horizontally by factor 1/2 (points reach the same y at half the x).","shortcut":"Inside multiplier b compresses by 1/b.","desmos":"Compare f(x) and f(2x) for a sample function."},
  {"id":"B32","domain":"ADV","skill":"quadratics","diff":4,"type":"work","format":"mc","stem":"A ball's height is h(t) = &minus;16t² + 48t + 64 feet. At what time t (seconds) does it hit the ground?","choices":["1","3","4","5"],"answer":2,"solution":"Ground: h=0 → &minus;16t²+48t+64=0 → divide by &minus;16: t²&minus;3t&minus;4=0 → (t&minus;4)(t+1)=0 → t=4 (t&gt;0).","shortcut":"Factor after dividing by &minus;16; take the positive root.","desmos":"Graph h(t); positive t-intercept is 4."},
  {"id":"B33","domain":"ADV","skill":"exponents","diff":4,"type":"work","format":"mc","stem":"If 4^(x) = 8^(x &minus; 1), what is the value of x?","choices":["1","2","3","6"],"answer":2,"solution":"Write base 2: 2^(2x) = 2^(3(x&minus;1)) → 2x = 3x &minus; 3 → x = 3.","shortcut":"Common base 2, equate exponents.","desmos":"Graph y=4^x and y=8^(x&minus;1); intersect at x=3."},
  {"id":"B34","domain":"ADV","skill":"factoring","diff":4,"type":"work","format":"grid","stem":"If 6x² + 11x &minus; 10 = (2x + a)(3x + b) for integers a and b, what is a + b?","answer":"3","solution":"(2x+5)(3x&minus;2) = 6x²&minus;4x+15x&minus;10 = 6x²+11x&minus;10. So a=5, b=&minus;2, and a+b = 5+(&minus;2) = 3.","shortcut":"Factor by grouping; a=5, b=&minus;2.","desmos":""},
  {"id":"B35","domain":"ADV","skill":"functions","diff":4,"type":"work","format":"grid","stem":"If f(x) = x² + 1 and g(x) = 2x &minus; 3, what is f(g(2))?","answer":"2","solution":"g(2) = 2(2)&minus;3 = 1. f(1) = 1² + 1 = 2.","shortcut":"Inside first: g(2)=1, then f(1)=2.","desmos":""},
  {"id":"B36","domain":"ADV","skill":"vertex-form","diff":5,"type":"work","format":"mc","stem":"The parabola y = ax² + bx + c has vertex (2, &minus;5) and passes through (0, 3). What is the value of a?","choices":["&minus;2","1","2","4"],"answer":2,"solution":"Vertex form y = a(x&minus;2)²&minus;5. Through (0,3): 3 = a(4)&minus;5 → 4a = 8 → a = 2.","shortcut":"Plug the extra point into vertex form and solve for a.","desmos":"Match a slider so the curve hits (0,3) with vertex (2,&minus;5)."},
  {"id":"B37","domain":"ADV","skill":"discriminant","diff":5,"type":"work","format":"mc","stem":"The equation x² + (k+1)x + k = 0 has a double root. What is the value of k?","choices":["&minus;1","0","1","3"],"answer":2,"solution":"Discriminant 0: (k+1)² &minus; 4k = 0 → k² + 2k + 1 &minus; 4k = 0 → k² &minus; 2k + 1 = 0 → (k&minus;1)² = 0 → k = 1.","shortcut":"Set discriminant to 0; (k&minus;1)²=0 gives k=1.","desmos":"Slide k; tangent to x-axis at k=1."},
  {"id":"B38","domain":"ADV","skill":"nonlinear-systems","diff":5,"type":"desmos","format":"grid","stem":"The parabola y = x² &minus; 4x + 7 and the line y = 2x + 2 intersect at two points, (x₁, y₁) and (x₂, y₂). What is the value of y₁ + y₂?","answer":"16","solution":"x²&minus;4x+7 = 2x+2 → x²&minus;6x+5=0 → (x&minus;1)(x&minus;5)=0 → x=1,5. y = 2x+2 gives y=4 and y=12. Sum = 4+12 = 16.","shortcut":"Find x-values from the quadratic, then plug into the line.","desmos":"Graph both; intersections at (1,4) and (5,12)."},
  {"id":"B39","domain":"ADV","skill":"polynomials","diff":4,"type":"work","format":"mc","stem":"When x³ + 2x² &minus; 5x + k is divided by (x &minus; 2), the remainder is 6. What is k?","choices":["&minus;6","0","6","12"],"answer":1,"solution":"Remainder Theorem: P(2)=6. P(2) = 8 + 8 &minus; 10 + k = 6 + k. Set 6+k = 6 → k = 0.","shortcut":"P(2) = remainder. 6 + k = 6.","desmos":""},
  {"id":"B40","domain":"ADV","skill":"rational-equations","diff":5,"type":"work","format":"grid","stem":"Solve for x: 3/(x&minus;1) &minus; 2/(x+1) = 10/(x²&minus;1).","answer":"5","solution":"Multiply by x²&minus;1 = (x&minus;1)(x+1): 3(x+1) &minus; 2(x&minus;1) = 10 → 3x+3 &minus;2x+2 = 10 → x + 5 = 10 → x = 5. Check x=5 ≠ ±1, valid.","shortcut":"Clear the common denominator (x&minus;1)(x+1), then solve and check domain.","desmos":"Graph both sides; intersect at x=5."},
  {"id":"B41","domain":"ADV","skill":"exponential-models","diff":4,"type":"work","format":"mc","stem":"An investment grows at 8% compounded annually. Which expression gives the number of years t to double, using logarithms?","choices":["t = log(2)/log(1.08)","t = log(1.08)/log(2)","t = 2/1.08","t = log(0.08)/log(2)"],"answer":0,"solution":"2 = 1.08^t → log 2 = t·log 1.08 → t = log 2 / log 1.08.","shortcut":"Take log of both sides, isolate t.","desmos":"Graph 1.08^t and y=2; intersection gives t≈9."},
  {"id":"B42","domain":"ADV","skill":"quadratics","diff":5,"type":"work","format":"mc","stem":"The roots of 2x² + bx + 3 = 0 are r and s with r·s + r + s = 2. What is b?","choices":["&minus;1","1","&minus;2","3"],"answer":0,"solution":"Product rs = 3/2, sum r+s = &minus;b/2. So 3/2 + (&minus;b/2) = 2 → &minus;b/2 = 1/2 → b = &minus;1.","shortcut":"Use rs=c/a, r+s=&minus;b/a.","desmos":""},
  {"id":"B43","domain":"ADV","skill":"factoring","diff":4,"type":"work","format":"mc","stem":"Factor completely and find the sum of all distinct real roots of x⁴ &minus; 13x² + 36 = 0.","choices":["0","5","13","36"],"answer":0,"solution":"Let u=x²: u²&minus;13u+36 = (u&minus;4)(u&minus;9)=0 → x²=4 or x²=9 → x=±2, ±3. Sum = 2&minus;2+3&minus;3 = 0.","shortcut":"Roots come in ± pairs, so they cancel to 0.","desmos":"Graph; four x-intercepts symmetric about 0."},
  {"id":"B44","domain":"ADV","skill":"function-transformations","diff":5,"type":"work","format":"mc","stem":"If f(x) has a maximum at (3, 10), the graph of y = &minus;f(x &minus; 1) + 4 has a minimum point. Where is it?","choices":["(4, &minus;6)","(2, 14)","(4, 14)","(2, &minus;6)"],"answer":0,"solution":"Shift right 1: x = 3+1 = 4. The reflection &minus;f turns the maximum into a minimum, mapping y=10 to &minus;10; then +4 gives y = &minus;10+4 = &minus;6. Minimum at (4, &minus;6).","shortcut":"Map the point: x→x+1, y→&minus;y+4. (3,10)→(4,&minus;6).","desmos":"Transform a test function and track the vertex."},
  {"id":"B45","domain":"ADV","skill":"radicals","diff":5,"type":"work","format":"grid","stem":"Solve for x: √(x + 5) + √(x) = 5.","answer":"4","solution":"√(x+5) = 5&minus;√x. Square: x+5 = 25 &minus;10√x + x → 5 = 25 &minus;10√x → 10√x = 20 → √x = 2 → x = 4. Check: √9+√4 = 3+2 = 5 ✓.","shortcut":"Isolate one radical, square, isolate the remaining radical.","desmos":"Graph y=√(x+5)+√x and y=5; intersect at x=4."},
  {"id":"B46","domain":"ADV","skill":"exponents","diff":4,"type":"work","format":"mc","stem":"If 9^(x) · 27^(2) = 3^(10), what is x?","choices":["1","2","4","8"],"answer":1,"solution":"9^x = 3^(2x), 27² = 3^6. So 3^(2x+6) = 3^10 → 2x+6=10 → x=2.","shortcut":"Convert all to base 3, add exponents, equate.","desmos":""},
  {"id":"B47","domain":"ADV","skill":"functions","diff":4,"type":"work","format":"mc","stem":"f is a linear function with f(1) = 4 and f(5) = 16. What is f⁻¹(10)?","choices":["3","7","10","2.5"],"answer":0,"solution":"Slope = (16&minus;4)/(5&minus;1) = 3. f(x) = 3x + 1 (since 3·1+1=4). f⁻¹(10): solve 3x+1=10 → x=3.","shortcut":"Find f, then solve f(x)=10.","desmos":"Graph the line; find x where y=10."},
  {"id":"B48","domain":"ADV","skill":"nonlinear-systems","diff":5,"type":"desmos","format":"grid","stem":"The circle x² + y² = 25 and the line y = x + 1 intersect at two points. What is the sum of the x-coordinates of these points?","answer":"-1","solution":"x² + (x+1)² = 25 → 2x² + 2x + 1 = 25 → 2x² + 2x &minus; 24 = 0 → x² + x &minus; 12 = 0. Sum of roots = &minus;1.","shortcut":"Substitute the line, sum of roots = &minus;b/a = &minus;1.","desmos":"Graph circle and line; intersections at x=3 and x=&minus;4."},
  {"id":"B49","domain":"ADV","skill":"polynomials","diff":5,"type":"desmos","format":"mc","stem":"The polynomial f(x) = x³ &minus; 6x² + 11x &minus; 6 has three integer roots. What is the product of the roots?","choices":["&minus;6","6","11","&minus;11"],"answer":1,"solution":"For x³+bx²+cx+d, product of roots = &minus;d (degree 3, leading 1): &minus;(&minus;6) = 6. (Roots are 1, 2, 3; product 6.)","shortcut":"Product of roots = &minus;d/a = 6.","desmos":"Graph; x-intercepts at 1, 2, 3."},
  {"id":"B50","domain":"ADV","skill":"quadratics","diff":5,"type":"work","format":"mc","stem":"The minimum value of f(x) = 3x² + 12x + k is 7. What is k?","choices":["&minus;5","7","12","19"],"answer":3,"solution":"Vertex x = &minus;12/6 = &minus;2. f(&minus;2) = 3(4) + 12(&minus;2) + k = 12 &minus; 24 + k = k &minus; 12. Set k&minus;12 = 7 → k = 19.","shortcut":"Min = k &minus; b²/(4a) = k &minus; 144/12 = k &minus; 12 = 7.","desmos":"Slide k until the vertex y-value reads 7."},
  {"id":"C11","domain":"PSD","skill":"percent","diff":1,"type":"mental","format":"mc","stem":"A store sells a backpack for $40. What is 15% of $40?","choices":["$4.00","$6.00","$8.00","$15.00"],"answer":1,"solution":"15% of 40 = 0.15 × 40 = 6.","shortcut":"10% is 4, 5% is 2, so 15% is 6.","desmos":""},
  {"id":"C12","domain":"PSD","skill":"ratios","diff":1,"type":"mental","format":"mc","stem":"In a class the ratio of boys to girls is 3 to 5. If there are 9 boys, how many girls are there?","choices":["12","15","18","24"],"answer":1,"solution":"9 boys ÷ 3 = 3 per part. Girls = 5 × 3 = 15.","shortcut":"Boys tripled from 3 to 9, so triple the 5 girls to 15.","desmos":""},
  {"id":"C13","domain":"PSD","skill":"mean-median","diff":1,"type":"mental","format":"mc","stem":"What is the mean of the data set 4, 8, 10, 6, 2?","choices":["5","6","7","10"],"answer":1,"solution":"Sum = 4+8+10+6+2 = 30. Mean = 30/5 = 6.","shortcut":"Total 30 over 5 values gives 6.","desmos":"mean([4,8,10,6,2])"},
  {"id":"C14","domain":"PSD","skill":"rates","diff":2,"type":"mental","format":"mc","stem":"A car travels 150 miles in 3 hours at a constant speed. At this rate, how many miles will it travel in 5 hours?","choices":["200","225","250","300"],"answer":2,"solution":"Speed = 150/3 = 50 mph. In 5 hours: 50 × 5 = 250 miles.","shortcut":"50 mph times 5 hours is 250.","desmos":""},
  {"id":"C15","domain":"PSD","skill":"proportions","diff":2,"type":"work","format":"mc","stem":"A recipe uses 2 cups of flour for every 3 cups of sugar. How many cups of flour are needed for 12 cups of sugar?","choices":["6","8","9","18"],"answer":1,"solution":"Set up 2/3 = x/12, so x = 2 × 12 / 3 = 8.","shortcut":"Sugar went from 3 to 12 (×4), so flour 2 × 4 = 8.","desmos":""},
  {"id":"C16","domain":"PSD","skill":"percent-change","diff":2,"type":"mental","format":"mc","stem":"A jacket originally priced at $80 is marked down to $60. What is the percent decrease in price?","choices":["20%","25%","30%","33%"],"answer":1,"solution":"Decrease = 80 − 60 = 20. Percent = 20/80 = 0.25 = 25%.","shortcut":"Drop of 20 out of original 80 is one quarter, 25%.","desmos":""},
  {"id":"C17","domain":"PSD","skill":"probability","diff":2,"type":"mental","format":"mc","stem":"A bag contains 5 red, 3 blue, and 2 green marbles. If one marble is drawn at random, what is the probability it is blue?","choices":["0.2","0.3","0.5","0.6"],"answer":1,"solution":"Total = 5+3+2 = 10. P(blue) = 3/10 = 0.3.","shortcut":"3 blue out of 10 total is 0.3.","desmos":""},
  {"id":"C18","domain":"PSD","skill":"units","diff":2,"type":"mental","format":"mc","stem":"A runner's speed is 6 meters per second. How many meters does the runner travel in 2 minutes?","choices":["360","600","720","1200"],"answer":2,"solution":"2 minutes = 120 seconds. Distance = 6 × 120 = 720 meters.","shortcut":"6 m/s for 120 s gives 720 m.","desmos":""},
  {"id":"C19","domain":"PSD","skill":"two-way-tables","diff":2,"type":"work","format":"mc","stem":"A survey of 100 people recorded whether they own a pet. <br>Of 60 men, 24 own a pet. Of 40 women, 22 own a pet.<br>How many of the 100 people surveyed own a pet?","choices":["42","44","46","48"],"answer":2,"solution":"Pet owners = 24 (men) + 22 (women) = 46.","shortcut":"Add the two pet-owner counts: 24 + 22 = 46.","desmos":""},
  {"id":"C20","domain":"PSD","skill":"statistics","diff":2,"type":"mental","format":"grid","stem":"What is the median of the data set 3, 7, 9, 12, 15, 20?","answer":"10.5","solution":"Six values; median is the average of the 3rd and 4th: (9+12)/2 = 10.5.","shortcut":"Middle two are 9 and 12; average is 10.5.","desmos":"median([3,7,9,12,15,20])"},
  {"id":"C21","domain":"PSD","skill":"percent","diff":3,"type":"work","format":"mc","stem":"At a restaurant, a meal costs $48 before tax. A 9% sales tax is added, and then a 20% tip is calculated on the after-tax total. What is the final amount paid?","choices":["$60.96","$62.78","$63.36","$57.60"],"answer":2,"solution":"After tax: 48 × 1.09 = 52.32. With 20% tip on the after-tax total: 52.32 × 1.20 = 62.784, which rounds to $62.78.","shortcut":"Multiply 48 × 1.09 × 1.20 = 62.784 ≈ 62.78.","desmos":"48*1.09*1.20"},
  {"id":"C22","domain":"PSD","skill":"percent-change","diff":4,"type":"work","format":"mc","stem":"A stock increases in value by 25% one year and then decreases by 20% the next year. What is the net percent change over the two years?","choices":["0% (no change)","5% increase","5% decrease","45% increase"],"answer":0,"solution":"Multiplier = 1.25 × 0.80 = 1.00, so the value returns to the original: 0% net change.","shortcut":"1.25 × 0.80 = 1, exactly even.","desmos":"1.25*0.80"},
  {"id":"C23","domain":"PSD","skill":"rates","diff":3,"type":"work","format":"mc","stem":"Pump A can fill a tank in 6 hours and pump B can fill the same tank in 12 hours. Working together, how many hours will they take to fill the tank?","choices":["3","4","8","9"],"answer":1,"solution":"Combined rate = 1/6 + 1/12 = 2/12 + 1/12 = 3/12 = 1/4 tank per hour. Time = 4 hours.","shortcut":"Rates add to 1/4 per hour, so 4 hours.","desmos":"1/(1/6+1/12)"},
  {"id":"C24","domain":"PSD","skill":"rates","diff":3,"type":"work","format":"mc","stem":"A metal block has a mass of 270 grams and a volume of 30 cubic centimeters. What is its density in grams per cubic centimeter?","choices":["7","8","9","10"],"answer":2,"solution":"Density = mass/volume = 270/30 = 9 g/cm³.","shortcut":"270 over 30 is 9.","desmos":"270/30"},
  {"id":"C25","domain":"PSD","skill":"two-way-tables","diff":4,"type":"work","format":"mc","stem":"A school surveyed students about transportation.<br><table border='1'><tr><td></td><td>Bus</td><td>Car</td><td>Total</td></tr><tr><td>Grade 9</td><td>45</td><td>30</td><td>75</td></tr><tr><td>Grade 10</td><td>35</td><td>40</td><td>75</td></tr><tr><td>Total</td><td>80</td><td>70</td><td>150</td></tr></table>If a student who takes the bus is selected at random, what is the probability the student is in Grade 9?","choices":["45/150","45/80","45/75","80/150"],"answer":1,"solution":"Conditioning on bus riders (80 total), Grade 9 bus riders = 45. P = 45/80.","shortcut":"Given bus, denominator is bus total 80; numerator is 45.","desmos":""},
  {"id":"C26","domain":"PSD","skill":"two-way-tables","diff":4,"type":"work","format":"grid","stem":"Using the same survey:<br><table border='1'><tr><td></td><td>Bus</td><td>Car</td><td>Total</td></tr><tr><td>Grade 9</td><td>45</td><td>30</td><td>75</td></tr><tr><td>Grade 10</td><td>35</td><td>40</td><td>75</td></tr><tr><td>Total</td><td>80</td><td>70</td><td>150</td></tr></table>What fraction of Grade 10 students take a car? Give your answer as a decimal.","answer":"0.53","solution":"Grade 10 car riders = 40 out of 75 Grade 10 students. 40/75 = 0.5333... ≈ 0.53.","shortcut":"40 over the Grade 10 total of 75 is about 0.53.","desmos":"40/75"},
  {"id":"C27","domain":"PSD","skill":"probability","diff":4,"type":"work","format":"mc","stem":"A box contains 4 defective and 16 non-defective light bulbs. Two bulbs are drawn at random without replacement. What is the probability that both are defective?","choices":["1/25","3/95","1/30","4/95"],"answer":1,"solution":"P = (4/20) × (3/19) = 12/380 = 3/95.","shortcut":"(4/20)(3/19) simplifies to 3/95.","desmos":"(4/20)*(3/19)"},
  {"id":"C28","domain":"PSD","skill":"mean-median","diff":4,"type":"work","format":"mc","stem":"The mean of five numbers is 18. When a sixth number is added, the mean becomes 20. What is the sixth number?","choices":["22","26","28","30"],"answer":3,"solution":"Sum of five = 5 × 18 = 90. Sum of six = 6 × 20 = 120. Sixth = 120 − 90 = 30.","shortcut":"New total 120 minus old total 90 is 30.","desmos":"6*20-5*18"},
  {"id":"C29","domain":"PSD","skill":"standard-deviation","diff":4,"type":"mental","format":"mc","stem":"Data set A is {10, 20, 30, 40, 50} and data set B is {28, 29, 30, 31, 32}. Both have a mean of 30. Which statement is true about their standard deviations?","choices":["A and B have equal standard deviations","A has a larger standard deviation than B","B has a larger standard deviation than A","Cannot be determined without more data"],"answer":1,"solution":"Standard deviation measures spread about the mean. Set A's values are far from 30; set B's are clustered near 30. So A has the larger standard deviation.","shortcut":"More spread means bigger SD; A is more spread out.","desmos":"stdev([10,20,30,40,50]) vs stdev([28,29,30,31,32])"},
  {"id":"C30","domain":"PSD","skill":"standard-deviation","diff":5,"type":"mental","format":"mc","stem":"Two classes take the same test. Class X scores are {70, 75, 80, 85, 90} and Class Y scores are {78, 79, 80, 81, 82}. Both classes have the same mean of 80. Which of the following correctly compares the data sets?","choices":["The means and standard deviations are both equal","The means are equal, but Class X has a greater standard deviation","The means are equal, but Class Y has a greater standard deviation","Class Y has a greater mean"],"answer":1,"solution":"Both means equal 80. Class X values deviate by up to 10 from the mean, while Class Y values deviate by at most 2. Greater spread means greater standard deviation, so Class X has the larger SD.","shortcut":"Same center, but X is wider, so X has bigger SD.","desmos":"stdev([70,75,80,85,90]) vs stdev([78,79,80,81,82])"},
  {"id":"C31","domain":"PSD","skill":"scatterplots","diff":3,"type":"desmos","format":"mc","stem":"A line of best fit for a scatterplot relating hours studied (x) and test score (y) is y = 6x + 52. Based on this model, what is the predicted score for a student who studies 5 hours?","choices":["57","78","82","88"],"answer":2,"solution":"y = 6(5) + 52 = 30 + 52 = 82.","shortcut":"6 times 5 is 30, plus 52 gives 82.","desmos":"Plot y_1 ~ a x_1 + b on the table, then evaluate at x=5; here 6*5+52=82."},
  {"id":"C32","domain":"PSD","skill":"scatterplots","diff":4,"type":"desmos","format":"mc","stem":"A line of best fit relating a car's age in years (x) and its value in dollars (y) is y = 24000 − 1800x. Which statement best interprets the slope in context?","choices":["The car's value increases by $1,800 each year","The car's value decreases by $1,800 each year","The car is worth $1,800 when new","The car loses 1,800% of its value each year"],"answer":1,"solution":"The slope −1800 means that for each additional year of age, the predicted value decreases by $1,800.","shortcut":"Negative slope of 1800 = drop of $1,800 per year.","desmos":"Slope a from y_1 ~ a x_1 + b is the dollar change per year of age."},
  {"id":"C33","domain":"PSD","skill":"scatterplots","diff":4,"type":"desmos","format":"mc","stem":"For the model y = 24000 − 1800x relating a car's age (x, years) to value (y, dollars), what is the y-intercept's meaning?","choices":["The car's value after 24,000 years","The age when the car is worthless","The car's predicted value when it is new (age 0)","The yearly depreciation"],"answer":2,"solution":"At x = 0, y = 24000, representing the predicted value of the car when new.","shortcut":"Intercept b is the value at age 0, i.e., when new.","desmos":"Intercept b from y_1 ~ a x_1 + b is the value when x=0."},
  {"id":"C34","domain":"PSD","skill":"data-models","diff":4,"type":"work","format":"mc","stem":"A bacteria population is modeled by P = 200(1.5)^t, where t is in hours. By what percent does the population increase each hour?","choices":["1.5%","15%","50%","150%"],"answer":2,"solution":"The growth factor 1.5 = 1 + 0.5, so the population increases by 50% each hour.","shortcut":"Base 1.5 means +50% per hour.","desmos":""},
  {"id":"C35","domain":"PSD","skill":"data-models","diff":5,"type":"work","format":"mc","stem":"The value of an investment is modeled by V = 5000(0.92)^t, where t is in years. Which of the following best describes the situation?","choices":["The investment grows by 92% per year","The investment loses 8% of its value each year","The investment loses $8 per year","The investment grows by 8% per year"],"answer":1,"solution":"The factor 0.92 = 1 − 0.08, so the investment decreases by 8% each year.","shortcut":"0.92 base means losing 8% annually.","desmos":""},
  {"id":"C36","domain":"PSD","skill":"sampling","diff":4,"type":"mental","format":"mc","stem":"A polling company estimates that 54% of voters support a measure, with a margin of error of 3%. Which of the following is the most appropriate conclusion?","choices":["Exactly 54% of all voters support the measure","Between 51% and 57% of all voters are likely to support the measure","Exactly 57% of voters support the measure","The measure will definitely pass"],"answer":1,"solution":"A 54% estimate with ±3% margin of error gives a plausible interval of 54−3 to 54+3, i.e., 51% to 57%.","shortcut":"Estimate ± margin: 54 ± 3 gives 51% to 57%.","desmos":""},
  {"id":"C37","domain":"PSD","skill":"sampling","diff":5,"type":"mental","format":"mc","stem":"Two surveys estimate the same quantity. Survey A uses 400 randomly selected people and Survey B uses 1,600 randomly selected people. Both use the same method. Which statement is most likely true?","choices":["Survey A will have a smaller margin of error","Survey B will have a smaller margin of error","Both will have the same margin of error","Margin of error does not depend on sample size"],"answer":1,"solution":"Larger random samples generally produce smaller margins of error. Since Survey B has the larger sample, it will have the smaller margin of error.","shortcut":"Bigger random sample means tighter estimate.","desmos":""},
  {"id":"C38","domain":"PSD","skill":"sampling","diff":4,"type":"mental","format":"mc","stem":"A researcher wants to estimate the average daily screen time of all students at a large university. Which sampling method would produce the most reliable, generalizable estimate?","choices":["Survey students leaving the computer lab","Survey a random sample of students from the full enrollment list","Survey only first-year students","Survey students who respond to an online ad"],"answer":1,"solution":"A random sample from the entire population avoids bias and allows results to be generalized to all students.","shortcut":"Random selection from the whole population is the unbiased choice.","desmos":""},
  {"id":"C39","domain":"PSD","skill":"percent","diff":3,"type":"work","format":"grid","stem":"In a town, 40% of residents own a bicycle. Of those bicycle owners, 25% ride daily. What percent of all residents ride a bicycle daily?","answer":"10","solution":"0.40 × 0.25 = 0.10 = 10%.","shortcut":"Multiply the percents as decimals: 0.4 × 0.25 = 0.10.","desmos":"0.40*0.25"},
  {"id":"C40","domain":"PSD","skill":"percent","diff":3,"type":"work","format":"mc","stem":"After a 30% discount, a television costs $280. What was the original price?","choices":["$364","$400","$364.50","$910"],"answer":1,"solution":"$280 is 70% of the original. Original = 280 / 0.70 = 400.","shortcut":"280 is 70%, so divide by 0.7 to get 400.","desmos":"280/0.70"},
  {"id":"C41","domain":"PSD","skill":"ratios","diff":3,"type":"work","format":"mc","stem":"A fruit punch is made by mixing juice and soda in a ratio of 5 to 3. If a batch contains 24 liters of punch, how many liters are juice?","choices":["9","12","15","18"],"answer":2,"solution":"Total parts = 5 + 3 = 8. Each part = 24/8 = 3 liters. Juice = 5 × 3 = 15 liters.","shortcut":"8 parts in 24 L means 3 L per part; juice is 5 parts = 15.","desmos":"5/8*24"},
  {"id":"C42","domain":"PSD","skill":"units","diff":3,"type":"work","format":"mc","stem":"A water tank is filled at a rate of 3 gallons per minute. How many gallons are added in 1.5 hours?","choices":["180","270","300","450"],"answer":1,"solution":"1.5 hours = 90 minutes. Gallons = 3 × 90 = 270.","shortcut":"90 minutes times 3 gal/min equals 270.","desmos":"3*90"},
  {"id":"C43","domain":"PSD","skill":"proportions","diff":3,"type":"work","format":"mc","stem":"On a map, 2 inches represents 50 miles. Two cities are 7 inches apart on the map. What is the actual distance between them?","choices":["100 miles","150 miles","175 miles","200 miles"],"answer":2,"solution":"Scale: 50/2 = 25 miles per inch. Distance = 7 × 25 = 175 miles.","shortcut":"25 miles per inch times 7 inches is 175.","desmos":"7*25"},
  {"id":"C44","domain":"PSD","skill":"statistics","diff":3,"type":"work","format":"mc","stem":"The data set 5, 8, 8, 10, 14 has its largest value changed from 14 to 24. Which measure changes the most?","choices":["The mode","The median","The mean","All change equally"],"answer":2,"solution":"Mode stays 8; median stays 8. Mean goes from 45/5 = 9 to 55/5 = 11, a change of 2. The mean changes the most.","shortcut":"Changing an extreme value affects the mean, not mode/median here.","desmos":"mean([5,8,8,10,24])"},
  {"id":"C45","domain":"PSD","skill":"probability","diff":3,"type":"work","format":"mc","stem":"A fair six-sided die is rolled once. What is the probability of rolling a number greater than 4?","choices":["1/6","1/3","1/2","2/3"],"answer":1,"solution":"Numbers greater than 4 are 5 and 6, so 2 outcomes out of 6: 2/6 = 1/3.","shortcut":"Two favorable outcomes out of six is 1/3.","desmos":""},
  {"id":"C46","domain":"PSD","skill":"percent-change","diff":5,"type":"work","format":"grid","stem":"A company's revenue grew by 10% in Year 1 and by 20% in Year 2 compared to the prior year. What was the total percent increase in revenue over the two-year period? Give your answer as a percent (number only).","answer":"32","solution":"Combined multiplier = 1.10 × 1.20 = 1.32, which is a 32% total increase.","shortcut":"1.10 × 1.20 = 1.32, so +32% (not 30%).","desmos":"1.10*1.20"},
  {"id":"C47","domain":"PSD","skill":"data-models","diff":5,"type":"work","format":"mc","stem":"A linear model predicts a plant's height (cm) as h = 2.5d + 4, where d is the number of days since planting. According to the model, how many days does it take for the plant to reach a height of 29 cm?","choices":["8","10","12","13"],"answer":1,"solution":"29 = 2.5d + 4, so 25 = 2.5d, giving d = 10.","shortcut":"Subtract 4 to get 25, divide by 2.5 to get 10.","desmos":"(29-4)/2.5"},
  {"id":"C48","domain":"PSD","skill":"mean-median","diff":5,"type":"work","format":"mc","stem":"A data set of 7 numbers has a median of 12. Six of the numbers are 4, 8, 10, 12, 15, and 20. If the seventh number is added and the median remains 12, which of the following could be the seventh number?","choices":["5","11","13","Any value at least 12"],"answer":3,"solution":"Ordered six values: 4, 8, 10, 12, 15, 20. Adding a 7th value gives 7 numbers; the median is the 4th. For the 4th value to be 12, the new number must be ≥ 12. If it were less than 12, the 4th value would shift to 10. So the seventh number must be at least 12.","shortcut":"To keep 12 as the 4th of 7 values, the new number can't fall below 12.","desmos":""},
  {"id":"C49","domain":"PSD","skill":"rates","diff":4,"type":"work","format":"mc","stem":"A printer prints 18 pages per minute. A faster printer prints 30 pages per minute. Working together, how long will it take them to print 960 pages?","choices":["18 minutes","20 minutes","24 minutes","32 minutes"],"answer":1,"solution":"Combined rate = 18 + 30 = 48 pages per minute. Time = 960 / 48 = 20 minutes.","shortcut":"48 pages/min into 960 pages is 20 minutes.","desmos":"960/48"},
  {"id":"C50","domain":"PSD","skill":"probability","diff":5,"type":"work","format":"grid","stem":"In a group of 200 people, 120 like tea and 90 like coffee. If 50 people like both tea and coffee, how many people like neither?","answer":"40","solution":"By inclusion-exclusion, those liking at least one = 120 + 90 − 50 = 160. Neither = 200 − 160 = 40.","shortcut":"Union is 120+90−50=160; 200−160=40 like neither.","desmos":"200-(120+90-50)"},
  {"id":"D11","domain":"GEO","skill":"angles","diff":1,"type":"mental","format":"mc","stem":"Two angles are supplementary. One measures 65°. What is the measure of the other angle?","choices":["25°","115°","135°","295°"],"answer":1,"solution":"Supplementary angles sum to 180°. 180° − 65° = 115°.","shortcut":"180 minus the given angle.","desmos":""},
  {"id":"D12","domain":"GEO","skill":"area","diff":1,"type":"mental","format":"mc","stem":"A rectangle has length 12 and width 5. What is its area?","choices":["17","34","60","120"],"answer":2,"solution":"Area = length × width = 12 × 5 = 60.","shortcut":"Multiply the two sides.","desmos":""},
  {"id":"D13","domain":"GEO","skill":"circles","diff":1,"type":"mental","format":"mc","stem":"A circle has radius 7. What is its circumference? (Use C = 2πr.)","choices":["7π","14π","49π","28π"],"answer":1,"solution":"C = 2πr = 2π(7) = 14π.","shortcut":"Circumference = 2πr; double the radius then times π.","desmos":""},
  {"id":"D14","domain":"GEO","skill":"angles","diff":2,"type":"mental","format":"mc","stem":"In a triangle, two angles measure 40° and 75°. What is the measure of the third angle?","choices":["55°","65°","75°","115°"],"answer":1,"solution":"Angles of a triangle sum to 180°. 180° − 40° − 75° = 65°.","shortcut":"180 minus the sum of the two known angles.","desmos":""},
  {"id":"D15","domain":"GEO","skill":"pythagorean","diff":2,"type":"mental","format":"mc","stem":"A right triangle has legs of length 6 and 8. What is the length of the hypotenuse?","choices":["10","14","48","100"],"answer":0,"solution":"Hypotenuse = √(6² + 8²) = √(36 + 64) = √100 = 10. (A 6-8-10 triangle, scaled 3-4-5.)","shortcut":"Recognize the 3-4-5 triple scaled by 2.","desmos":""},
  {"id":"D16","domain":"GEO","skill":"coordinate","diff":2,"type":"mental","format":"mc","stem":"What is the midpoint of the segment with endpoints (2, 4) and (8, 10)?","choices":["(5, 7)","(6, 6)","(10, 14)","(3, 3)"],"answer":0,"solution":"Midpoint = ((2+8)/2, (4+10)/2) = (5, 7).","shortcut":"Average the x-values and the y-values.","desmos":""},
  {"id":"D17","domain":"GEO","skill":"special-triangles","diff":2,"type":"work","format":"mc","stem":"In a 45-45-90 right triangle, each leg has length 5. What is the length of the hypotenuse?","choices":["5","5√2","10","5√3"],"answer":1,"solution":"In a 45-45-90 triangle the hypotenuse equals a leg times √2, so 5√2.","shortcut":"Leg × √2 for the hypotenuse in 45-45-90.","desmos":""},
  {"id":"D18","domain":"GEO","skill":"volume","diff":2,"type":"mental","format":"grid","stem":"A rectangular box (right rectangular prism) has dimensions 3 by 4 by 5. What is its volume?","answer":"60","solution":"Volume = length × width × height = 3 × 4 × 5 = 60.","shortcut":"Multiply all three dimensions.","desmos":""},
  {"id":"D19","domain":"GEO","skill":"trig","diff":2,"type":"mental","format":"mc","stem":"In right triangle ABC, the right angle is at C. The side opposite angle A has length 3 and the hypotenuse has length 5. What is sin A?","choices":["3/5","4/5","3/4","5/3"],"answer":0,"solution":"sin A = opposite/hypotenuse = 3/5.","shortcut":"SOH: sine = opposite over hypotenuse.","desmos":""},
  {"id":"D20","domain":"GEO","skill":"perimeter","diff":2,"type":"mental","format":"mc","stem":"An equilateral triangle has a perimeter of 27. What is the length of one side?","choices":["3","9","13.5","81"],"answer":1,"solution":"All three sides are equal: 27 ÷ 3 = 9.","shortcut":"Divide perimeter by 3.","desmos":""},
  {"id":"D21","domain":"GEO","skill":"lines-angles","diff":3,"type":"work","format":"mc","stem":"Lines m and n are parallel and cut by a transversal. One interior angle on the upper line is (3x + 10)°, and the co-interior (same-side interior) angle on the lower line is (2x + 30)°. What is the value of x?","choices":["28","20","32","40"],"answer":0,"solution":"Same-side interior angles are supplementary: (3x+10)+(2x+30)=180 → 5x+40=180 → 5x=140 → x=28.","shortcut":"Co-interior angles sum to 180 for parallel lines.","desmos":""},
  {"id":"D22","domain":"GEO","skill":"area","diff":3,"type":"work","format":"mc","stem":"A trapezoid has parallel sides of length 8 and 14 and a height of 6. What is its area?","choices":["33","66","132","84"],"answer":1,"solution":"Area = ½(b₁+b₂)h = ½(8+14)(6) = ½(22)(6) = 66.","shortcut":"Average the parallel sides, times the height.","desmos":""},
  {"id":"D23","domain":"GEO","skill":"circles","diff":3,"type":"work","format":"mc","stem":"A circle has area 36π. What is its circumference?","choices":["6π","12π","36π","18π"],"answer":1,"solution":"Area = πr² = 36π → r² = 36 → r = 6. Circumference = 2πr = 12π.","shortcut":"Find r from the area, then 2πr.","desmos":""},
  {"id":"D25","domain":"GEO","skill":"coordinate","diff":3,"type":"work","format":"mc","stem":"What is the distance between the points (1, 2) and (7, 10)?","choices":["10","14","√52","8"],"answer":0,"solution":"Distance = √((7−1)² + (10−2)²) = √(36 + 64) = √100 = 10.","shortcut":"Distance formula; recognize 6-8-10.","desmos":"Plot both points and read distance, or use distance formula in input."},
  {"id":"D26","domain":"GEO","skill":"special-triangles","diff":3,"type":"work","format":"mc","stem":"In a 30-60-90 right triangle, the side opposite the 30° angle has length 7. What is the length of the side opposite the 60° angle?","choices":["7","7√3","14","7√2"],"answer":1,"solution":"Sides are in ratio 1 : √3 : 2 (opposite 30 : 60 : 90). The short side is 7, so the side opposite 60° is 7√3.","shortcut":"Short leg × √3 = long leg in 30-60-90.","desmos":""},
  {"id":"D27","domain":"GEO","skill":"arc-sector","diff":3,"type":"work","format":"mc","stem":"A circle has radius 10. A central angle of 72° subtends an arc. What is the length of that arc?","choices":["2π","4π","10π","20π"],"answer":1,"solution":"Arc length = (θ/360)·2πr = (72/360)·2π(10) = (1/5)(20π) = 4π.","shortcut":"Fraction of circle (72/360 = 1/5) times full circumference 20π.","desmos":""},
  {"id":"D28","domain":"GEO","skill":"volume","diff":3,"type":"work","format":"mc","stem":"A right circular cylinder has radius 3 and height 10. What is its volume? (V = πr²h.)","choices":["30π","90π","60π","300π"],"answer":1,"solution":"V = πr²h = π(3²)(10) = π(9)(10) = 90π.","shortcut":"Square the radius, times height, times π.","desmos":""},
  {"id":"D29","domain":"GEO","skill":"trig","diff":3,"type":"work","format":"mc","stem":"In a right triangle, the angle θ has cos θ = 5/13. The triangle is a 5-12-13 right triangle. What is tan θ?","choices":["12/13","5/12","12/5","13/12"],"answer":2,"solution":"cos θ = adjacent/hyp = 5/13, so adjacent = 5, hyp = 13, opposite = 12. tan θ = opposite/adjacent = 12/5.","shortcut":"5-12-13 triple; tan = opp/adj = 12/5.","desmos":""},
  {"id":"D30","domain":"GEO","skill":"pythagorean","diff":3,"type":"work","format":"grid","stem":"A right triangle has a hypotenuse of length 17 and one leg of length 8. What is the length of the other leg?","answer":"15","solution":"Other leg = √(17² − 8²) = √(289 − 64) = √225 = 15. (An 8-15-17 triple.)","shortcut":"Recognize the 8-15-17 Pythagorean triple.","desmos":""},
  {"id":"D31","domain":"GEO","skill":"coordinate","diff":3,"type":"work","format":"mc","stem":"A line passes through the points (−2, 1) and (4, 13). What is the slope of the line?","choices":["2","3","1/2","12"],"answer":0,"solution":"Slope = (13 − 1)/(4 − (−2)) = 12/6 = 2.","shortcut":"Rise over run: change in y over change in x.","desmos":""},
  {"id":"D33","domain":"GEO","skill":"radians","diff":3,"type":"mental","format":"mc","stem":"An angle measures 135°. What is its measure in radians?","choices":["3π/4","2π/3","5π/6","4π/3"],"answer":0,"solution":"Radians = degrees × π/180 = 135 × π/180 = 3π/4.","shortcut":"Multiply degrees by π/180 and reduce.","desmos":""},
  {"id":"D34","domain":"GEO","skill":"circle-equations","diff":4,"type":"work","format":"mc","stem":"The equation of a circle is x² + y² − 6x + 8y − 11 = 0. What are the coordinates of its center?","choices":["(3, −4)","(−3, 4)","(6, −8)","(−6, 8)"],"answer":0,"solution":"Complete the square: (x²−6x) + (y²+8y) = 11 → (x−3)²−9 + (y+4)²−16 = 11 → (x−3)²+(y+4)² = 36. Center is (3, −4).","shortcut":"Center is (−B/2, −C/2) from x²+y²+Bx+Cy+D=0: (3, −4).","desmos":"Type the equation into Desmos; it draws the circle and you can read center."},
  {"id":"D35","domain":"GEO","skill":"circle-equations","diff":4,"type":"work","format":"grid","stem":"The equation of a circle is x² + y² − 6x + 8y − 11 = 0. What is the radius of the circle?","answer":"6","solution":"Completing the square gives (x−3)²+(y+4)² = 9+16+11 = 36, so r = √36 = 6.","shortcut":"After completing the square, r = √(right side) = √36 = 6.","desmos":"Graph the equation in Desmos and measure the radius."},
  {"id":"D36","domain":"GEO","skill":"trig","diff":4,"type":"work","format":"mc","stem":"If sin(x°) = cos(40°), and 0 < x < 90, what is the value of x?","choices":["40","50","60","140"],"answer":1,"solution":"sin and cosine are cofunctions: sin(x°) = cos(90° − x°). Setting 90 − x = 40 gives x = 50.","shortcut":"Complementary-angle identity: x + 40 = 90, so x = 50.","desmos":""},
  {"id":"D37","domain":"GEO","skill":"arc-sector","diff":4,"type":"work","format":"mc","stem":"A sector of a circle has radius 12 and a central angle of 30°. What is the area of the sector?","choices":["6π","12π","24π","144π"],"answer":1,"solution":"Sector area = (θ/360)·πr² = (30/360)·π(144) = (1/12)(144π) = 12π.","shortcut":"Fraction 30/360 = 1/12 of the full area 144π.","desmos":""},
  {"id":"D38","domain":"GEO","skill":"volume","diff":4,"type":"work","format":"mc","stem":"A cone and a cylinder have the same radius 6 and the same height 9. What is the volume of the cone? (V_cone = (1/3)πr²h.)","choices":["108π","324π","36π","972π"],"answer":0,"solution":"V = (1/3)π(6²)(9) = (1/3)π(36)(9) = (1/3)(324π) = 108π.","shortcut":"Cone is one-third of the cylinder volume (324π/3 = 108π).","desmos":""},
  {"id":"D39","domain":"GEO","skill":"volume","diff":4,"type":"work","format":"mc","stem":"A sphere has a volume of 36π. What is its radius? (V = (4/3)πr³.)","choices":["2","3","4","27"],"answer":1,"solution":"(4/3)πr³ = 36π → r³ = 36·3/4 = 27 → r = 3.","shortcut":"Drop π, solve r³ = 27, so r = 3.","desmos":""},
  {"id":"D40","domain":"GEO","skill":"coordinate","diff":4,"type":"work","format":"mc","stem":"Triangle has vertices A(0, 0), B(6, 0), and C(6, 8). What is the perimeter of the triangle?","choices":["24","20","14","48"],"answer":0,"solution":"AB = 6, BC = 8 (vertical), AC = √(6²+8²) = √100 = 10. Perimeter = 6 + 8 + 10 = 24.","shortcut":"It's a 6-8-10 right triangle; sum the sides.","desmos":"Plot the three points and use distance formula for each side."},
  {"id":"D42","domain":"GEO","skill":"right-triangles","diff":4,"type":"work","format":"grid","stem":"In right triangle PQR, the right angle is at Q. PQ = 9 and QR = 12. Point S is on PR such that QS is the altitude to the hypotenuse. What is the length of PR (the hypotenuse)?","answer":"15","solution":"PR = √(9² + 12²) = √(81 + 144) = √225 = 15. (A 9-12-15 = 3·(3-4-5) triangle.)","shortcut":"Recognize 9-12-15 as scaled 3-4-5.","desmos":""},
  {"id":"D43","domain":"GEO","skill":"area","diff":4,"type":"work","format":"mc","stem":"A square is inscribed in a circle of radius 5√2. What is the area of the square?","choices":["100","50","200","25"],"answer":0,"solution":"The diagonal of the square equals the diameter = 2·5√2 = 10√2. For a square, side = diagonal/√2 = 10√2/√2 = 10. Area = 10² = 100.","shortcut":"Diagonal = diameter; area = diagonal²/2 = (10√2)²/2 = 200/2 = 100.","desmos":""},
  {"id":"D44","domain":"GEO","skill":"trig","diff":4,"type":"work","format":"mc","stem":"In right triangle ABC with the right angle at B, angle A = 30° and the hypotenuse AC = 14. What is the length of side BC (opposite angle A)?","choices":["7","7√3","14","7√2"],"answer":0,"solution":"BC = AC·sin A = 14·sin 30° = 14·(1/2) = 7.","shortcut":"sin 30° = 1/2, so opposite = half the hypotenuse.","desmos":""},
  {"id":"D46","domain":"GEO","skill":"radians","diff":4,"type":"work","format":"mc","stem":"A circle has radius 9. An arc has length 6π. What is the central angle of that arc in radians?","choices":["2π/3","3π/4","π/3","6π"],"answer":0,"solution":"Arc length = rθ → 6π = 9θ → θ = 6π/9 = 2π/3 radians.","shortcut":"θ = arc length / radius.","desmos":""},
  {"id":"D47","domain":"GEO","skill":"coordinate","diff":4,"type":"work","format":"grid","stem":"The endpoints of a diameter of a circle are (1, 2) and (7, 10). What is the radius of the circle?","answer":"5","solution":"Diameter length = √((7−1)²+(10−2)²) = √(36+64) = √100 = 10. Radius = 10/2 = 5.","shortcut":"Find diameter with distance formula, then halve.","desmos":"Plot the endpoints; the midpoint is the center and half the distance is the radius."},
  {"id":"D49","domain":"GEO","skill":"volume","diff":5,"type":"work","format":"mc","stem":"A solid consists of a cylinder of radius 3 and height 8 with a hemisphere of radius 3 attached on top. What is the total volume of the solid? (V_cyl = πr²h, V_sphere = (4/3)πr³.)","choices":["90π","72π","108π","84π"],"answer":0,"solution":"Cylinder: π(3²)(8) = 72π. Hemisphere: (1/2)(4/3)π(3³) = (2/3)π(27) = 18π. Total = 72π + 18π = 90π.","shortcut":"Hemisphere volume = (2/3)πr³ = 18π; add to cylinder 72π.","desmos":""},
  {"id":"D50","domain":"GEO","skill":"trig","diff":5,"type":"work","format":"grid","stem":"In a right triangle, angle A and angle B are the two acute angles. If sin A = 0.6, what is cos B? Give a decimal.","answer":"0.6","solution":"In a right triangle the acute angles are complementary (A + B = 90°), so cos B = cos(90° − A) = sin A = 0.6.","shortcut":"Complementary acute angles: cos B = sin A directly.","desmos":""},
  {"id":"D52","domain":"GEO","skill":"coordinate","diff":5,"type":"desmos","format":"mc","stem":"Line ℓ passes through (1, 2) and (5, 4). Line k is perpendicular to ℓ and passes through (5, 4). Which point also lies on line k?","choices":["(7, 0)","(7, 8)","(3, 5)","(9, 6)"],"answer":0,"solution":"Slope of ℓ = (4−2)/(5−1) = 1/2. Perpendicular slope = −2. Line k: y − 4 = −2(x − 5) → y = −2x + 14. At x = 7: y = −2(7)+14 = 0, giving (7, 0).","shortcut":"Perpendicular slope is −2; test each point in y = −2x + 14.","desmos":"Graph both lines in Desmos and see which listed point sits on line k."},
  {"id":"D53","domain":"GEO","skill":"arc-sector","diff":5,"type":"work","format":"grid","stem":"A circle has radius 6. A sector has a central angle of 2π/3 radians. What is the area of the sector? Round to two decimals.","answer":"37.70","solution":"Sector area = ½r²θ = ½(36)(2π/3) = 18·(2π/3) = 12π ≈ 37.70.","shortcut":"Area = ½r²θ = 12π ≈ 37.70.","desmos":""},
  {"id":"D58","domain":"GEO","skill":"angles","diff":5,"type":"work","format":"grid","stem":"A regular polygon has interior angles each measuring 150°. How many sides does the polygon have?","answer":"12","solution":"Each interior angle = (n−2)·180/n = 150 → (n−2)·180 = 150n → 180n − 360 = 150n → 30n = 360 → n = 12.","shortcut":"Exterior angle = 180 − 150 = 30; n = 360/30 = 12.","desmos":""},
  {"id":"D59","domain":"GEO","skill":"circle-equations","diff":5,"type":"desmos","format":"mc","stem":"The circle x² + y² + 4x − 10y + 20 = 0 has a center and radius. What is the radius?","choices":["3","9","7","√29"],"answer":0,"solution":"Complete the square: (x²+4x) + (y²−10y) = −20 → (x+2)²−4 + (y−5)²−25 = −20 → (x+2)²+(y−5)² = 9. Radius = √9 = 3.","shortcut":"Move constant, complete squares; right side 9 gives r = 3.","desmos":"Enter the equation in Desmos; it plots the circle so you can read the radius."},
  {"id":"D60","domain":"GEO","skill":"radians","diff":5,"type":"work","format":"grid","stem":"A wheel of radius 2 feet rolls without slipping. The wheel turns through an angle of 5π/2 radians. How far does the wheel travel along the ground, in feet? Round to two decimals.","answer":"15.71","solution":"Distance = arc length = rθ = 2·(5π/2) = 5π ≈ 15.71 feet.","shortcut":"Rolling distance = rθ = 5π ≈ 15.71.","desmos":""},
  {"id":"A51","domain":"ALG","skill":"systems","diff":4,"type":"work","format":"mc","stem":"The system of equations 6x &minus; 2y = 10 and 3x + ky = 7 has no solution. What is the value of k?","choices":["&minus;1","1","&minus;2","3"],"answer":0,"solution":"No solution means the lines are parallel: equal slopes, different intercepts. First line: y = 3x &minus; 5 (slope 3). Second: 3x + ky = 7 → y = (&minus;3/k)x + 7/k (slope &minus;3/k). Set &minus;3/k = 3 → k = &minus;1. Check intercepts differ: 7/k = &minus;7 ≠ &minus;5, so truly no solution.","shortcut":"Parallel ⇒ slopes equal. Slope of Ax+By=C is &minus;A/B: 6/2 = 3 must equal &minus;3/k → k = &minus;1.","desmos":"Add a slider k, type both equations, and drag k until the lines look parallel (never intersect) at k = &minus;1."},
  {"id":"A52","domain":"ALG","skill":"linear-models","diff":3,"type":"work","format":"grid","stem":"A plumber charges a flat $40 service fee plus $0.25 per mile driven. For one job the total charge was $97.50. How many miles were driven?","answer":"230","solution":"40 + 0.25m = 97.50 → 0.25m = 57.50 → m = 57.50/0.25 = 230 miles.","shortcut":"Subtract the fixed $40, then divide by the per-mile rate: 57.5 ÷ 0.25 = 230.","desmos":"y=40+0.25x and y=97.5; intersection at x=230."},
  {"id":"A53","domain":"ALG","skill":"absolute-value","diff":5,"type":"mental","format":"mc","stem":"How many integer values of x satisfy |2x &minus; 5| &lt; 7 ?","choices":["5","6","7","8"],"answer":1,"solution":"|2x&minus;5| &lt; 7 → &minus;7 &lt; 2x&minus;5 &lt; 7 → &minus;2 &lt; 2x &lt; 12 → &minus;1 &lt; x &lt; 6. The integers strictly between &minus;1 and 6 are 0,1,2,3,4,5 — that is 6 values.","shortcut":"Unfold the absolute value into a double inequality, isolate x, then count integers strictly inside (endpoints excluded because it's &lt;).","desmos":"Graph y=|2x-5| and y=7; count integer x where the V is below the line."},
  {"id":"B51","domain":"ADV","skill":"exponential-growth","diff":4,"type":"work","format":"mc","stem":"A bacteria culture doubles every 3 hours. If there are 500 bacteria now, how many will there be in 12 hours?","choices":["2,000","4,000","8,000","16,000"],"answer":2,"solution":"Number of doublings = 12 ÷ 3 = 4. Final = 500 · 2⁴ = 500 · 16 = 8,000.","shortcut":"Count the doublings (4), then multiply by 2⁴ = 16: 500·16 = 8,000.","desmos":"y=500·2^(x/3); read y at x=12 → 8000."},
  {"id":"B52","domain":"ADV","skill":"quadratics","diff":4,"type":"work","format":"grid","stem":"The equation 2x² + bx &minus; 6 = 0 has solutions x = 3 and x = r. What is the value of r?","answer":"-1","solution":"Product of the roots = c/a = &minus;6/2 = &minus;3. Since one root is 3: 3·r = &minus;3 → r = &minus;1.","shortcut":"Product of roots = c/a. Here c/a = &minus;3, and 3·r = &minus;3 gives r = &minus;1 instantly.","desmos":"Plug r as a slider into 2x²+bx-6 or just factor 2(x-3)(x+1)=2x²-4x-6; the second root is -1."},
  {"id":"B53","domain":"ADV","skill":"exponents","diff":5,"type":"work","format":"mc","stem":"If 4ˣ = 8^(x &minus; 1), what is the value of x?","choices":["1","2","3","6"],"answer":2,"solution":"Write both sides base 2: 4ˣ = 2^(2x) and 8^(x&minus;1) = 2^(3(x&minus;1)) = 2^(3x&minus;3). Equal bases → 2x = 3x &minus; 3 → x = 3.","shortcut":"Convert to a common base 2, then just set the exponents equal: 2x = 3x&minus;3.","desmos":"Graph y=4^x and y=8^(x-1); the intersection is at x=3."},
  {"id":"C51","domain":"PSD","skill":"percent","diff":4,"type":"mental","format":"mc","stem":"A price is increased by 20%, and then the new price is decreased by 20%. The final price is what percent of the original price?","choices":["96%","98%","100%","104%"],"answer":0,"solution":"Multiply the factors: 1.20 · 0.80 = 0.96, so the final price is 96% of the original. (Successive percent changes multiply, not add.)","shortcut":"+20% then &minus;20% = ×1.2×0.8 = ×0.96 → 96%. It never returns to 100%.","desmos":"1.2*0.8 = 0.96."},
  {"id":"C52","domain":"PSD","skill":"statistics","diff":3,"type":"work","format":"mc","stem":"The data set 4, 8, 8, 12, x has a mean of 9. What is the value of x?","choices":["11","12","13","14"],"answer":2,"solution":"Mean 9 over 5 values means the total is 9·5 = 45. The four known values sum to 4+8+8+12 = 32, so x = 45 &minus; 32 = 13.","shortcut":"Required sum = mean × count = 45. Subtract the known total (32): x = 13.","desmos":"Solve mean([4,8,8,12,x])=9, or 45-32 = 13."},
  {"id":"C53","domain":"PSD","skill":"probability","diff":5,"type":"work","format":"mc","stem":"A bag holds 5 red, 3 blue, and 2 green marbles. Two marbles are drawn at random without replacement. What is the probability that both are red?","choices":["1/4","2/9","5/18","1/5"],"answer":1,"solution":"P(first red) = 5/10. After removing one red, P(second red) = 4/9. Multiply: (5/10)(4/9) = 20/90 = 2/9.","shortcut":"Sequential without replacement: (5/10)·(4/9) = 2/9. (Using 5/10 twice — with replacement — wrongly gives 1/4.)","desmos":"(5/10)*(4/9) → 0.2222 = 2/9."},
  {"id":"D61","domain":"GEO","skill":"trig-cofunction","diff":4,"type":"mental","format":"mc","stem":"In a right triangle, A and B are the two acute angles. If sin A = 0.6, what is cos B?","choices":["0.6","0.8","0.36","0.75"],"answer":0,"solution":"A and B are complementary (they sum to 90°). The cofunction identity gives cos B = cos(90° &minus; A) = sin A = 0.6.","shortcut":"In a right triangle the acute angles are complementary, so cos(one) = sin(other): cos B = sin A = 0.6.","desmos":""},
  {"id":"D62","domain":"GEO","skill":"3d-geometry","diff":5,"type":"work","format":"grid","stem":"A rectangular box has dimensions 2 by 3 by 6. What is the length of the longest diagonal of the box?","answer":"7","solution":"The space diagonal of a box is √(l²+w²+h²) = √(2²+3²+6²) = √(4+9+36) = √49 = 7.","shortcut":"Space diagonal = √(sum of squares) = √(4+9+36) = √49 = 7.","desmos":"sqrt(2^2+3^2+6^2) = 7."},
  {"id":"D63","domain":"GEO","skill":"circle-angles","diff":3,"type":"mental","format":"mc","stem":"An inscribed angle in a circle subtends (intercepts) an arc of 80°. What is the measure of the inscribed angle?","choices":["20°","40°","80°","160°"],"answer":1,"solution":"An inscribed angle is half of its intercepted arc: 80° ÷ 2 = 40°.","shortcut":"Inscribed angle = ½ × intercepted arc = 40°. (A central angle would equal the full 80°.)","desmos":""},
  {"id":"A54","domain":"ALG","skill":"systems","diff":5,"type":"work","format":"grid","stem":"For what value of a does the system ax + 4y = 9 and 3x + 2y = 5 have no solution?","answer":"6","solution":"No solution means the lines are parallel: the x and y coefficients are proportional but the constants are not. Match the ratio: a/3 = 4/2 = 2, so a = 6. Check constants: 6x+4y=9 vs (3x+2y=5)×2 = 6x+4y=10 — same left side, different right side, so they never meet.","shortcut":"Match the x:y coefficient ratio (4/2 = 2) → a = 2·3 = 6; constants differ, so it's no solution (not infinitely many).","desmos":"Add a slider a, graph both lines, and find the a where they become parallel (never intersect)."},
  {"id":"A55","domain":"ALG","skill":"absolute-value","diff":5,"type":"work","format":"mc","stem":"How many integer values of x satisfy |3x − 4| ≤ 11 ?","choices":["7","8","9","10"],"answer":1,"solution":"−11 ≤ 3x − 4 ≤ 11 → −7 ≤ 3x ≤ 15 → −7/3 ≤ x ≤ 5, i.e. about −2.33 ≤ x ≤ 5. The integers −2, −1, 0, 1, 2, 3, 4, 5 — that's 8 values.","shortcut":"Solve the compound inequality, then count integers in [−2.33, 5]: from −2 to 5 is 8.","desmos":"Graph y=|3x−4| and y=11; count the integer x-values where the V is at or below the line."},
  {"id":"A56","domain":"ALG","skill":"linear-word-problems","diff":4,"type":"work","format":"mc","stem":"One gym charges a $30 sign-up fee plus $18 per month. A rival has no sign-up fee but charges $24 per month. After how many months do the two cost the same?","choices":["3","4","5","6"],"answer":2,"solution":"Set the costs equal: 30 + 18m = 24m → 30 = 6m → m = 5.","shortcut":"Sign-up gap $30 ÷ monthly gap $6 = 5 months.","desmos":"Graph y=30+18x and y=24x, then click the intersection → x = 5."},
  {"id":"B54","domain":"ADV","skill":"nonlinear-systems","diff":5,"type":"work","format":"grid","stem":"The parabola y = x² − 3x + 5 and the line y = x + 2 intersect at two points. What is the sum of the x-coordinates of the two intersection points?","answer":"4","solution":"Set equal: x² − 3x + 5 = x + 2 → x² − 4x + 3 = 0. The sum of the roots is −(−4)/1 = 4. (The roots are 1 and 3.)","shortcut":"At intersections the equations are equal; sum of roots = −b/a = 4 — no need to actually solve.","desmos":"Graph both; the two intersection x-values add to 4."},
  {"id":"B55","domain":"ADV","skill":"quadratics","diff":5,"type":"work","format":"mc","stem":"The function f(x) = 2x² + 8x + k has a minimum value of 3. What is k?","choices":["3","8","11","19"],"answer":2,"solution":"The vertex is at x = −8/(2·2) = −2. f(−2) = 2(4) + 8(−2) + k = 8 − 16 + k = k − 8. Set k − 8 = 3 → k = 11.","shortcut":"Minimum value = k − b²/(4a) = k − 64/8 = k − 8 = 3 → k = 11.","desmos":"Add a slider k; raise it until the parabola's lowest point sits at y = 3."},
  {"id":"B56","domain":"ADV","skill":"radicals","diff":5,"type":"work","format":"grid","stem":"Solve for x: √(2x + 7) − x = 2.","answer":"1","solution":"Isolate the root: √(2x+7) = x + 2. Square: 2x + 7 = x² + 4x + 4 → x² + 2x − 3 = 0 → (x+3)(x−1) = 0 → x = 1 or x = −3. Check both: x=1 gives √9 − 1 = 2 ✓; x=−3 gives √1 − (−3) = 4 ✗ (extraneous). So x = 1.","shortcut":"Square once, factor, then test for extraneous roots — only x = 1 survives.","desmos":"Graph y=√(2x+7) and y=x+2; they meet at x = 1."},
  {"id":"B57","domain":"ADV","skill":"exponents","diff":4,"type":"work","format":"mc","stem":"If 9^(x + 1) = 27^x, what is the value of x?","choices":["1","2","3","4"],"answer":1,"solution":"Write both sides base 3: 9 = 3², 27 = 3³, so 3^(2(x+1)) = 3^(3x) → 2x + 2 = 3x → x = 2.","shortcut":"Common base 3: 2(x+1) = 3x → x = 2.","desmos":"Graph y=9^(x+1) and y=27^x; the intersection is at x = 2."},
  {"id":"C54","domain":"PSD","skill":"percent-change","diff":5,"type":"work","format":"mc","stem":"A stock price falls 20% on Monday, then rises 30% on Tuesday. Compared with its price before Monday, what is the net change?","choices":["−4%","+4%","+6%","+10%"],"answer":1,"solution":"Multiply the factors: 0.80 × 1.30 = 1.04, a 4% increase. (You can't just add −20% and +30%.)","shortcut":"Chain the multipliers: 0.8 × 1.3 = 1.04 → +4%.","desmos":"Type 0.8*1.3 → 1.04, i.e. 4% above the original."},
  {"id":"C55","domain":"PSD","skill":"probability","diff":5,"type":"work","format":"grid","stem":"A drawer holds 4 black socks and 6 white socks. Two socks are drawn at random without replacement. What is the probability that both are black? Give your answer as a fraction.","answer":"2/15","solution":"P(first black) = 4/10. After removing one black, P(second black) = 3/9. Multiply: (4/10)(3/9) = 12/90 = 2/15.","shortcut":"Multiply the sequential probabilities and reduce: 12/90 = 2/15.","desmos":"Type (4/10)*(3/9) → 0.1333… = 2/15."},
  {"id":"D64","domain":"GEO","skill":"circle-equations","diff":5,"type":"work","format":"grid","stem":"The circle x² + y² − 6x + 8y + 9 = 0 has what radius?","answer":"4","solution":"Complete the square: (x² − 6x) + (y² + 8y) = −9 → (x−3)² − 9 + (y+4)² − 16 = −9 → (x−3)² + (y+4)² = 16. Radius = √16 = 4.","shortcut":"r = √((−6/2)² + (8/2)² − 9) = √(9 + 16 − 9) = √16 = 4.","desmos":"Enter the equation; Desmos plots the circle so you can read off radius 4."},
  {"id":"D65","domain":"GEO","skill":"radians","diff":5,"type":"work","format":"grid","stem":"A sector of a circle of radius 9 has a central angle of 4π/9 radians. What is the arc length? Round to two decimals.","answer":"12.57","solution":"Arc length s = rθ = 9 × (4π/9) = 4π ≈ 12.57.","shortcut":"s = rθ; the 9s cancel, leaving 4π ≈ 12.57.","desmos":"Type 4*pi → 12.566… ≈ 12.57."},
  {"id":"D66","domain":"GEO","skill":"trig-cofunction","diff":4,"type":"mental","format":"mc","stem":"In right triangle ABC the right angle is at C. If sin A = 5/13, what is cos B?","choices":["5/13","12/13","13/5","1"],"answer":0,"solution":"A and B are the two acute angles, so they are complementary (A + B = 90°). The cofunction identity gives cos B = cos(90° − A) = sin A = 5/13.","shortcut":"Acute angles of a right triangle are complementary, so cos B = sin A = 5/13.","desmos":""},
  {"id":"A57","domain":"ALG","skill":"mixtures","diff":4,"type":"work","format":"mc","stem":"A chemist mixes a 30% acid solution with a 70% acid solution to make 20 liters of a 45% acid solution. How many liters of the 30% solution are used?","choices":["7.5","10","12.5","15"],"answer":2,"solution":"Let x = liters of 30% solution; then 20 − x is the 70% solution. Acid balance: 0.30x + 0.70(20 − x) = 0.45(20) = 9. So 0.30x + 14 − 0.70x = 9 → −0.40x = −5 → x = 12.5 liters.","shortcut":"45% is closer to 30% than to 70% (15 vs 25 apart), so use MORE of the 30% — the 70:30 split by distance gives 25/40 of 20 = 12.5 L.","desmos":"Graph y=0.30x+0.70(20−x) and y=9; intersection at x=12.5."},
  {"id":"A58","domain":"ALG","skill":"systems","diff":5,"type":"work","format":"mc","stem":"The system 2x − 3y = 7 and ax − 9y = b has infinitely many solutions. What is the value of a + b?","choices":["13","21","27","28"],"answer":2,"solution":"Infinitely many solutions means the second equation is a constant multiple of the first. Matching the y-terms: −9 = k(−3) → k = 3. Then a = 3(2) = 6 and b = 3(7) = 21. So a + b = 27.","shortcut":"Scale factor from −3 to −9 is 3; multiply the whole first equation by 3: a = 6, b = 21, sum 27.","desmos":"With a=6, b=21 the two equations graph as the identical line — infinitely many solutions."},
  {"id":"A59","domain":"ALG","skill":"work-rate","diff":5,"type":"work","format":"grid","stem":"Working together, pipes A and B fill a tank in 3 hours. Pipe A alone fills it in 5 hours. How many hours does pipe B alone take to fill the tank?","answer":"7.5","solution":"Rates add: 1/5 + 1/B = 1/3. So 1/B = 1/3 − 1/5 = 5/15 − 3/15 = 2/15, giving B = 15/2 = 7.5 hours.","shortcut":"Combined rate 1/3 minus A's rate 1/5 = 2/15; invert → 7.5 hours.","desmos":"Solve 1/5 + 1/x = 1/3 by graphing y=1/5+1/x and y=1/3; intersection at x=7.5."},
  {"id":"B58","domain":"ADV","skill":"quadratics","diff":5,"type":"desmos","format":"mc","stem":"A ball is thrown upward and its height, in feet, after t seconds is h(t) = −16t² + 48t + 6. What is the maximum height, in feet, that the ball reaches?","choices":["36","42","48","54"],"answer":1,"solution":"The vertex occurs at t = −48/(2·−16) = 1.5 s. h(1.5) = −16(2.25) + 48(1.5) + 6 = −36 + 72 + 6 = 42 feet.","shortcut":"Max value = c − b²/(4a) = 6 − 48²/(4·−16) = 6 + 36 = 42.","desmos":"Graph y=−16x²+48x+6 and click the peak → (1.5, 42); the max height is 42."},
  {"id":"B59","domain":"ADV","skill":"exponential-models","diff":4,"type":"desmos","format":"mc","stem":"An investment is modeled by V = 8000(1.5)^(t/4) dollars, where t is the number of years. What is the value of the investment after 12 years?","choices":["18,000","21,000","27,000","36,000"],"answer":2,"solution":"After 12 years the exponent is 12/4 = 3, so V = 8000(1.5)³ = 8000(3.375) = 27,000 dollars.","shortcut":"The value multiplies by 1.5 every 4 years: 8000 → 12,000 → 18,000 → 27,000 across 12 years.","desmos":"Define V(t)=8000*1.5^(t/4) and type V(12) → 27000."},
  {"id":"B60","domain":"ADV","skill":"algebraic-manipulation","diff":5,"type":"work","format":"mc","stem":"If x > 0 and x² + 1/x² = 14, what is the value of x + 1/x?","choices":["√14","4","12","16"],"answer":1,"solution":"Note (x + 1/x)² = x² + 2 + 1/x² = 14 + 2 = 16. Since x > 0, x + 1/x > 0, so x + 1/x = √16 = 4.","shortcut":"Square the target: it equals the given expression plus 2, so √(14+2) = 4.","desmos":"Solve x²+1/x²=14 for x>0 (x≈3.73), then evaluate x+1/x → 4."},
  {"id":"C56","domain":"PSD","skill":"statistics","diff":4,"type":"mental","format":"mc","stem":"A set of 5 numbers has a mean of 20. A sixth number is added and the mean of all six numbers becomes 22. What is the sixth number?","choices":["22","24","30","32"],"answer":3,"solution":"Original sum = 5 × 20 = 100. New sum = 6 × 22 = 132. The sixth number = 132 − 100 = 32.","shortcut":"To pull 5 numbers up by 2 each (+10 total) and itself reach the new mean, it must be 22 + 10 = 32.","desmos":"Solve (100 + n)/6 = 22 → n = 32."},
  {"id":"C57","domain":"PSD","skill":"conditional-probability","diff":5,"type":"work","format":"grid","stem":"Of 200 people surveyed, 120 own a car and 50 own both a car and a bike. If a person who owns a car is chosen at random, what is the probability that the person also owns a bike? Give your answer as a fraction.","answer":"5/12","solution":"Restrict to the 120 car owners. Among them, 50 also own a bike. P(bike | car) = 50/120 = 5/12.","shortcut":"Conditional probability — divide within the car-owner group: 50/120 = 5/12.","desmos":"Type 50/120 → 0.4166… = 5/12."},
  {"id":"D67","domain":"GEO","skill":"circle-equations","diff":5,"type":"work","format":"grid","stem":"The circle x² + y² = 25 and the line y = x + 1 intersect at two points. What is the product of the x-coordinates of those two points?","answer":"-12","solution":"Substitute: x² + (x + 1)² = 25 → 2x² + 2x + 1 = 25 → 2x² + 2x − 24 = 0 → x² + x − 12 = 0. The product of the roots is c/a = −12. (The points have x = 3 and x = −4.)","shortcut":"After substituting, the product of roots is just c/a = −12 — no need to solve the quadratic.","desmos":"Graph x²+y²=25 and y=x+1; the intersection x-values 3 and −4 multiply to −12."},
  {"id":"D68","domain":"GEO","skill":"radians","diff":4,"type":"mental","format":"mc","stem":"What is the exact value of sin(5π/6)?","choices":["−√3/2","−1/2","1/2","√3/2"],"answer":2,"solution":"5π/6 = 150°, a second-quadrant angle with reference angle 30°. Sine is positive in Q2, so sin(5π/6) = sin(30°) = 1/2.","shortcut":"Reference angle 30°, Q2 → sine positive → 1/2.","desmos":"Set Desmos to radians and type sin(5π/6) → 0.5."},
  {"id":"A60","domain":"ALG","skill":"systems","diff":5,"type":"work","format":"mc","stem":"A café sells small coffees for $3 and large coffees for $5. One day it sold a total of 240 coffees and collected $920. How many large coffees were sold?","choices":["80","100","120","140"],"answer":1,"solution":"Let s and l be the counts: s + l = 240 and 3s + 5l = 920. Substitute s = 240 − l: 3(240 − l) + 5l = 920 → 720 + 2l = 920 → 2l = 200 → l = 100.","shortcut":"If all 240 were small you'd get $720; each large adds $2, and 920 − 720 = 200, so 200/2 = 100 larges.","desmos":"Enter s+l=240 and 3s+5l=920 as a system; the solution gives l=100 (s=140)."},
  {"id":"A61","domain":"ALG","skill":"absolute-value","diff":4,"type":"mental","format":"mc","stem":"How many integer values of x satisfy |2x − 7| < 5?","choices":["3","4","5","6"],"answer":1,"solution":"|2x − 7| < 5 means −5 < 2x − 7 < 5 → 2 < 2x < 12 → 1 < x < 6. The integers strictly between 1 and 6 are 2, 3, 4, 5 — four values.","shortcut":"Strict inequality on both ends, so exclude the endpoints x=1 and x=6: that leaves 4 integers.","desmos":"Graph y=|2x-7| and y=5; count integer x where the V dips below the line."},
  {"id":"A62","domain":"ALG","skill":"slope","diff":5,"type":"work","format":"grid","stem":"In the xy-plane, the line through (−2, 5) and (4, k) is perpendicular to the line 3x + 2y = 12. What is the value of k?","answer":"9","solution":"3x + 2y = 12 has slope −3/2, so a perpendicular line has slope 2/3. The slope through the two points is (k − 5)/(4 − (−2)) = (k − 5)/6. Set (k − 5)/6 = 2/3 → k − 5 = 4 → k = 9.","shortcut":"Perpendicular slope is the negative reciprocal of −3/2, namely 2/3; over a run of 6 the rise is 4, so k = 5 + 4 = 9.","desmos":"Plot 3x+2y=12 to read slope −3/2; perpendicular slope 2/3 gives k = 5 + (2/3)(6) = 9."},
  {"id":"B61","domain":"ADV","skill":"discriminant","diff":5,"type":"mental","format":"mc","stem":"The equation 2x² + bx + 8 = 0 has exactly one real solution. What is the greatest possible value of b?","choices":["−8","4","8","16"],"answer":2,"solution":"One real solution means the discriminant is zero: b² − 4(2)(8) = 0 → b² − 64 = 0 → b = ±8. The greatest value is 8.","shortcut":"Set b² = 4ac = 64, so b = ±8; take the larger, 8.","desmos":"Graph 2x²+bx+8 with a slider for b; the parabola is tangent to the x-axis at b=8 and b=−8."},
  {"id":"B62","domain":"ADV","skill":"nonlinear-systems","diff":5,"type":"work","format":"grid","stem":"The graphs of y = x² − 4x + 7 and y = 2x + 2 intersect at two points. What is the sum of the x-coordinates of those points?","answer":"6","solution":"Set equal: x² − 4x + 7 = 2x + 2 → x² − 6x + 5 = 0. The sum of the roots is −(−6)/1 = 6. (The points have x = 1 and x = 5.)","shortcut":"After moving everything to one side, the sum of roots is −b/a = 6 — no need to factor.","desmos":"Graph both equations; intersection x-values 1 and 5 sum to 6."},
  {"id":"B63","domain":"ADV","skill":"polynomials","diff":4,"type":"desmos","format":"mc","stem":"The polynomial p(x) = x³ − 2x² − 5x + 6 has x = 1 as a root. Which of the following is also a root of p?","choices":["−3","−2","2","4"],"answer":1,"solution":"Since x = 1 is a root, divide: p(x) = (x − 1)(x² − x − 6) = (x − 1)(x − 3)(x + 2). The roots are 1, 3, and −2. Of the choices, only −2 is a root.","shortcut":"Factor out (x − 1) to get x² − x − 6 = (x − 3)(x + 2); the remaining roots are 3 and −2.","desmos":"Graph y=x³−2x²−5x+6; it crosses the x-axis at x = −2, 1, and 3."},
  {"id":"C58","domain":"PSD","skill":"percent-change","diff":4,"type":"mental","format":"mc","stem":"A stock's price increased by 25% in January and then decreased by 20% in February. Compared with its price at the start of January, the price at the end of February is:","choices":["5% lower","exactly the same","5% higher","45% higher"],"answer":1,"solution":"Multiply the factors: 1.25 × 0.80 = 1.00, so the price returns exactly to its starting value — no net change.","shortcut":"A 25% rise then a 20% fall: 1.25 × 0.8 = 1, so it's unchanged.","desmos":"Type 1.25*0.80 → 1, i.e., 100% of the original."},
  {"id":"C59","domain":"PSD","skill":"mean-median","diff":4,"type":"work","format":"grid","stem":"The mean of a list of 6 numbers is 14. A seventh number is added to the list and the new mean is 16. What is the seventh number?","answer":"28","solution":"The original sum is 6 × 14 = 84. The new sum must be 7 × 16 = 112. The seventh number is 112 − 84 = 28.","shortcut":"Total has to rise from 84 to 112, a jump of 28 — that's the new value.","desmos":"Type 7*16 − 6*14 → 28."},
  {"id":"C60","domain":"PSD","skill":"probability","diff":5,"type":"desmos","format":"mc","stem":"A bag contains 5 red marbles and 3 blue marbles. Two marbles are drawn at random without replacement. What is the probability that both marbles are red?","choices":["5/14","15/56","25/64","5/8"],"answer":0,"solution":"P(first red) = 5/8. After removing one red, P(second red) = 4/7. Multiply: (5/8)(4/7) = 20/56 = 5/14.","shortcut":"Multiply the two stage probabilities 5/8 · 4/7 = 5/14; the denominator drops by one because there's no replacement.","desmos":"Type (5/8)*(4/7) → 0.3571… = 5/14."},
  {"id":"D69","domain":"GEO","skill":"circle-equations","diff":5,"type":"work","format":"mc","stem":"The equation x² + y² − 6x + 8y + 9 = 0 represents a circle in the xy-plane. What is the radius of the circle?","choices":["2","4","16","√34"],"answer":1,"solution":"Complete the square: (x² − 6x) + (y² + 8y) = −9 → (x − 3)² − 9 + (y + 4)² − 16 = −9 → (x − 3)² + (y + 4)² = 16. The radius is √16 = 4.","shortcut":"Half of −6 is −3 and half of 8 is 4; the right side becomes −9 + 9 + 16 = 16, so r = 4.","desmos":"Type x²+y²−6x+8y+9=0 directly; Desmos draws a circle of radius 4 centered at (3, −4)."},
  {"id":"D70","domain":"GEO","skill":"trig","diff":3,"type":"mental","format":"mc","stem":"In right triangle ABC, the right angle is at C. If sin A = 3/5, what is cos A?","choices":["3/4","3/5","4/5","5/3"],"answer":2,"solution":"sin A = opposite/hypotenuse = 3/5, so the legs and hypotenuse form a 3-4-5 triangle. cos A = adjacent/hypotenuse = 4/5.","shortcut":"Recognize the 3-4-5 triple: if sin = 3/5 then cos = 4/5.","desmos":"Compute cos(arcsin(3/5)) → 0.8 = 4/5."},
  {"id":"A63","domain":"ALG","skill":"nonlinear-systems","diff":5,"type":"desmos","format":"mc","stem":"The system y = x² − 4x + 7 and y = 2x + 2 has two solutions. What is the sum of the x-coordinates of the two solutions?","choices":["−6","5","6","11"],"answer":2,"solution":"Set equal: x² − 4x + 7 = 2x + 2 → x² − 6x + 5 = 0. By the sum-of-roots rule, the sum of the x-coordinates is −b/a = 6. (The roots are x = 1 and x = 5.)","shortcut":"Move everything to one side to get x² − 6x + 5 = 0; sum of roots = −(−6)/1 = 6 — no need to factor.","desmos":"Graph both equations and click the two intersection points (1, 4) and (5, 12); add the x-values 1 + 5 = 6."},
  {"id":"A64","domain":"ALG","skill":"slope","diff":4,"type":"work","format":"mc","stem":"A line in the xy-plane passes through the points (a, 0) and (0, a + 6) and has a slope of −3. What is the value of a?","choices":["−3","2","3","9"],"answer":2,"solution":"Slope = ((a + 6) − 0)/(0 − a) = (a + 6)/(−a) = −3. Then a + 6 = 3a, so 6 = 2a and a = 3. (The points are (3, 0) and (0, 9).)","shortcut":"Set (a+6)/(−a) = −3, cross-multiply to a + 6 = 3a, giving a = 3.","desmos":"Add a slider a, plot (a,0) and (0,a+6), and drag a until the segment's slope reads −3 (at a = 3)."},
  {"id":"A65","domain":"ALG","skill":"absolute-value","diff":5,"type":"work","format":"grid","stem":"For how many integer values of x is |x − 4| + |x + 2| = 6?","answer":"7","solution":"The expression is the total distance from x to 4 and to −2. Since 4 and −2 are 6 apart, the sum equals 6 exactly when x lies between them (inclusive): −2 ≤ x ≤ 4. The integers are −2, −1, 0, 1, 2, 3, 4 — that is 7 values. (Outside this interval the sum exceeds 6.)","shortcut":"|x−4|+|x+2| is minimized at the distance between the points, 6, for ALL x in [−2, 4]; count the integers: 7.","desmos":"Graph y=|x-4|+|x+2| and y=6; the graphs coincide along the flat bottom from x=-2 to x=4 — 7 integer x-values."},
  {"id":"B64","domain":"ADV","skill":"discriminant","diff":5,"type":"work","format":"mc","stem":"The equation 2x² + kx + 8 = 0 has exactly one real solution, and k < 0. What is the value of k?","choices":["−8","−4","8","16"],"answer":0,"solution":"Exactly one real solution means the discriminant is 0: k² − 4(2)(8) = 0 → k² = 64 → k = ±8. Since k < 0, k = −8.","shortcut":"Set b² = 4ac: k² = 64, so k = −8 (take the negative root).","desmos":"Add a slider k and graph y=2x²+kx+8; slide k until the parabola just touches the x-axis — it does so at k = −8 (and k = 8)."},
  {"id":"B65","domain":"ADV","skill":"exponential-models","diff":5,"type":"desmos","format":"grid","stem":"An investment of $2000 grows according to V(t) = 2000(1.04)ᵗ dollars after t years. After how many whole years does the value first exceed $3000?","answer":"11","solution":"Solve 2000(1.04)ᵗ = 3000 → 1.04ᵗ = 1.5 → t = ln(1.5)/ln(1.04) ≈ 10.34. The value first exceeds $3000 at the next whole year: t = 11. (Check: V(10) ≈ $2960, V(11) ≈ $3079.)","shortcut":"1.04ᵗ must beat 1.5; logs give t ≈ 10.3, so the first whole year over is 11.","desmos":"Graph y=2000(1.04)^x and y=3000; the intersection is near x≈10.3, so the first integer year above is 11."},
  {"id":"B66","domain":"ADV","skill":"function-composition","diff":4,"type":"work","format":"mc","stem":"The function f is defined by f(x) = 2x − 1. If f(g(x)) = 6x + 5 for all x, which of the following is g(x)?","choices":["3x + 2","3x + 3","6x + 6","3x + 6"],"answer":1,"solution":"f(g(x)) = 2·g(x) − 1 = 6x + 5. So 2·g(x) = 6x + 6 and g(x) = 3x + 3.","shortcut":"Undo f: add 1 then halve. (6x + 5 + 1)/2 = (6x + 6)/2 = 3x + 3.","desmos":"Define f(x)=2x-1 and g(x)=3x+3, then graph f(g(x)); it lands exactly on y=6x+5."},
  {"id":"C61","domain":"PSD","skill":"statistics","diff":5,"type":"mental","format":"mc","stem":"A data set of 10 numbers has a mean of 14. When the largest value is removed, the mean of the remaining 9 numbers is 12. What was the value that was removed?","choices":["20","26","32","38"],"answer":2,"solution":"Total of all 10 = 10 × 14 = 140. Total of remaining 9 = 9 × 12 = 108. Removed value = 140 − 108 = 32.","shortcut":"Two totals: 140 and 108; the gap, 32, is the removed number.","desmos":"Type 10*14 - 9*12 → 32."},
  {"id":"C62","domain":"PSD","skill":"percent-change","diff":4,"type":"mental","format":"mc","stem":"A stock's value rises 20% in one year and then falls 20% the next year. At the end of the two years, its value is what percent of its original value?","choices":["96%","98%","100%","104%"],"answer":0,"solution":"Multiply the factors: 1.20 × 0.80 = 0.96 = 96%. A gain then an equal-percent loss does not return to the start.","shortcut":"(1 + r)(1 − r) = 1 − r² = 1 − 0.04 = 0.96 → 96%.","desmos":"Type 1.2*0.8 → 0.96."},
  {"id":"D71","domain":"GEO","skill":"circle-equations","diff":5,"type":"desmos","format":"mc","stem":"The circle with equation x² + y² + 10x − 4y − 7 = 0 is tangent to the vertical line x = c, where c > 0. What is the value of c?","choices":["1","6","7","11"],"answer":0,"solution":"Complete the square: (x + 5)² − 25 + (y − 2)² − 4 − 7 = 0 → (x + 5)² + (y − 2)² = 36. Center (−5, 2), radius 6. The circle's rightmost point is x = −5 + 6 = 1, so the tangent vertical line with c > 0 is x = 1.","shortcut":"Center x = −5, radius 6; the right edge sits at −5 + 6 = 1.","desmos":"Graph x²+y²+10x-4y-7=0 and a vertical line x=c with a slider; the right side just touches at c = 1."},
  {"id":"D72","domain":"GEO","skill":"trig","diff":5,"type":"work","format":"grid","stem":"For an acute angle x (in degrees), sin(x°) = cos(3x°). What is the value of x?","answer":"22.5","solution":"Cofunction identity: cos(3x°) = sin((90 − 3x)°). So sin(x°) = sin((90 − 3x)°), giving x = 90 − 3x → 4x = 90 → x = 22.5. (Check: sin 22.5° ≈ 0.383 and cos 67.5° ≈ 0.383.)","shortcut":"Complementary angles: x + 3x = 90 → x = 22.5.","desmos":"In degree mode, graph y=sin(x) and y=cos(3x); the first acute intersection is at x = 22.5."},
  {"id":"D73","domain":"GEO","skill":"similar-triangles","diff":4,"type":"work","format":"mc","stem":"Two similar triangles have areas in the ratio 9 : 16. A side of the smaller triangle has length 6. What is the length of the corresponding side of the larger triangle?","choices":["7.5","8","9","10.67"],"answer":1,"solution":"For similar figures, the ratio of areas is the square of the ratio of sides. √(9/16) = 3/4, so the side ratio (small : large) is 3 : 4. The corresponding side = 6 × (4/3) = 8.","shortcut":"Take the square root of the area ratio (3/4) to get the side ratio; 6 × 4/3 = 8.","desmos":"Type 6*sqrt(16/9) → 8."},
  {"id":"A66","domain":"ALG","skill":"linear-systems","diff":4,"type":"work","format":"mc","stem":"The system of equations 3x + ky = 12 and 6x + 4y = 7 has no solution. What is the value of k?","choices":["2","−2","8","1/2"],"answer":0,"solution":"A system of two lines has no solution when the lines are parallel (equal slopes) but not identical. The coefficients of x and y must be proportional: 3/6 = k/4. So k/4 = 1/2 and k = 2. (The constants 12 and 7 are not in the same ratio, so the lines are parallel, not coincident — confirming no solution.)","shortcut":"Match the x-coefficient ratio to the y-coefficient ratio: 3/6 = k/4 → k = 2.","desmos":"Graph both equations with a slider for k; the lines become parallel (never crossing) exactly at k = 2."},
  {"id":"A67","domain":"ALG","skill":"linear-systems","diff":5,"type":"work","format":"mc","stem":"The system of equations ax + 6y = 18 and 4x + 8y = b has infinitely many solutions. What is the value of a + b?","choices":["27","24","3","30"],"answer":0,"solution":"Infinitely many solutions means the two equations describe the same line, so all three coefficient ratios match: a/4 = 6/8 = 18/b. From 6/8 = 3/4: a/4 = 3/4 gives a = 3, and 18/b = 3/4 gives b = 24. Thus a + b = 27.","shortcut":"Same line ⇒ every ratio equals 6/8 = 3/4. a = 4·¾ = 3 and b = 18 ÷ ¾ = 24, so a + b = 27.","desmos":"Set sliders a and b and graph both lines; they overlap completely only at a = 3, b = 24."},
  {"id":"A68","domain":"ALG","skill":"absolute-value","diff":4,"type":"mental","format":"mc","stem":"For which of the following values of k does the equation 3|x − 2| + 4 = k have no solution?","choices":["2","4","7","10"],"answer":0,"solution":"Since |x − 2| ≥ 0, the smallest possible value of 3|x − 2| + 4 is 4 (at x = 2). The equation has a solution only when k ≥ 4. Among the choices, only k = 2 is below this minimum, so it gives no solution.","shortcut":"The left side bottoms out at 4; any k less than 4 is impossible. Only 2 < 4.","desmos":"Graph y=3|x-2|+4 and y=k; the horizontal line misses the V entirely when k < 4 (e.g. k = 2)."},
  {"id":"B67","domain":"ADV","skill":"nonlinear-systems","diff":5,"type":"work","format":"grid","stem":"The system y = x² + bx + 5 and y = 3x + 1 has exactly one real solution. What is the greatest possible value of b?","answer":"7","solution":"Set the expressions equal: x² + bx + 5 = 3x + 1 → x² + (b − 3)x + 4 = 0. Exactly one solution means the discriminant is 0: (b − 3)² − 4(1)(4) = 0 → (b − 3)² = 16 → b − 3 = ±4 → b = 7 or b = −1. The greatest value is 7.","shortcut":"Subtract the line to get x² + (b−3)x + 4 = 0; tangency needs (b−3)² = 16, so b = 7 or −1 — take 7.","desmos":"Graph the parabola with a slider b and the line y=3x+1; the parabola just touches the line at b = 7 (and b = −1)."},
  {"id":"B68","domain":"ADV","skill":"circle-equations","diff":5,"type":"desmos","format":"mc","stem":"In the xy-plane, the graph of x² + y² − 6x + 8y − 11 = 0 is a circle. What is the radius of the circle?","choices":["5","6","25","36"],"answer":1,"solution":"Complete the square in both variables: (x² − 6x) + (y² + 8y) = 11 → (x − 3)² − 9 + (y + 4)² − 16 = 11 → (x − 3)² + (y + 4)² = 36. The radius is √36 = 6. (Choice 36 forgets the square root; choice 5 comes from dropping the constant 11.)","shortcut":"Halve and square each linear coefficient (−3→9, 4→16), add to 11: 9 + 16 + 11 = 36; radius = √36 = 6.","desmos":"Type x²+y²-6x+8y-11=0; Desmos draws the circle — read the radius (6) from the grid, or convert to (x-3)²+(y+4)²=36."},
  {"id":"B69","domain":"ADV","skill":"exponential-models","diff":4,"type":"desmos","format":"mc","stem":"A radioactive sample with an initial mass of 240 grams decays so that its mass is cut in half every 8 years. Which expression gives the mass, in grams, remaining after t years?","choices":["240(½)^(t/8)","240(½)^(8t)","240(2)^(t/8)","120(½)^(t/8)"],"answer":0,"solution":"Halving every 8 years means the number of half-lives elapsed in t years is t/8. Each half-life multiplies the mass by ½, so mass = 240(½)^(t/8). (Check: at t = 8, 240(½)¹ = 120, exactly half.)","shortcut":"Base ½ for halving; exponent is (time)/(half-life) = t/8. Coefficient stays the starting 240.","desmos":"Graph y=240(0.5)^(x/8); at x=8 it reads 120 and at x=16 it reads 60 — each 8 years halves it."},
  {"id":"C63","domain":"PSD","skill":"ratios","diff":4,"type":"mental","format":"mc","stem":"In a survey of 400 people, the ratio of those who prefer tea to those who prefer coffee is 3 : 5, and everyone chose one of the two. How many more people prefer coffee than tea?","choices":["50","100","150","200"],"answer":1,"solution":"The ratio 3 : 5 has 3 + 5 = 8 equal parts, so each part is 400 ÷ 8 = 50 people. Tea = 3(50) = 150, coffee = 5(50) = 250. The difference is 250 − 150 = 100 (which is also just 2 parts × 50).","shortcut":"8 parts → 50 each; the gap is (5 − 3) = 2 parts = 2 × 50 = 100.","desmos":"Type 400/8*2 → 100."},
  {"id":"C64","domain":"PSD","skill":"probability","diff":5,"type":"work","format":"grid","stem":"A bag contains 5 red, 3 blue, and 2 green marbles. Two marbles are drawn at random without replacement. What is the probability that both marbles are red? (Enter as a fraction.)","answer":"2/9","solution":"There are 10 marbles. P(first red) = 5/10. After removing one red, 4 reds remain among 9 marbles, so P(second red) = 4/9. Multiply: (5/10)(4/9) = 20/90 = 2/9. (A common error is (5/10)² = 1/4, which wrongly assumes replacement.)","shortcut":"Without replacement: (5/10)(4/9) = 2/9. Don't reuse 5/10 twice.","desmos":"Type (5/10)*(4/9) → 0.2222…, which is 2/9."},
  {"id":"C65","domain":"PSD","skill":"statistics","diff":4,"type":"work","format":"grid","stem":"The mean of a list of 5 numbers is 12. When one number is removed from the list, the mean of the remaining 4 numbers is 14. What was the value of the number that was removed?","answer":"4","solution":"Total of the 5 numbers = 5 × 12 = 60. Total of the remaining 4 = 4 × 14 = 56. The removed number = 60 − 56 = 4. (Note: removing a small value below the mean raises the average — a common surprise.)","shortcut":"Compare totals: 60 − 56 = 4.","desmos":"Type 5*12 - 4*14 → 4."},
  {"id":"D74","domain":"GEO","skill":"circle-equations","diff":5,"type":"work","format":"mc","stem":"In the xy-plane, the line y = x + k is tangent to the circle x² + y² = 8. What is a positive value of k?","choices":["4","2","2√2","8"],"answer":0,"solution":"The circle is centered at the origin with radius √8 = 2√2. A line is tangent when its distance from the center equals the radius. Write the line as x − y + k = 0; the distance from (0, 0) is |k|/√(1² + (−1)²) = |k|/√2. Set equal to 2√2: |k|/√2 = 2√2 → |k| = 2√2 · √2 = 4. A positive value is k = 4.","shortcut":"Distance from origin to x − y + k = 0 is |k|/√2; set it to the radius 2√2 ⇒ |k| = 4.","desmos":"Graph x²+y²=8 and y=x+k with a slider; the line just touches the circle at k = 4 (and k = −4)."},
  {"id":"D75","domain":"GEO","skill":"trig","diff":4,"type":"mental","format":"mc","stem":"In right triangle ABC, the right angle is at C and sin(A) = 0.6. What is the value of tan(A)?","choices":["0.75","1.33","0.8","0.6"],"answer":0,"solution":"sin(A) = 0.6 = 3/5 corresponds to the 3-4-5 right triangle: opposite = 3, hypotenuse = 5, so the adjacent leg = 4 and cos(A) = 4/5. Then tan(A) = sin/cos = 0.6/0.8 = 3/4 = 0.75.","shortcut":"0.6 → 3-4-5 triangle; tan = opposite/adjacent = 3/4 = 0.75.","desmos":"Type sin⁻¹(0.6) to get the angle, then tan of it → 0.75."},
  {"id":"D76","domain":"GEO","skill":"right-triangles","diff":5,"type":"work","format":"mc","stem":"In right triangle ABC, the right angle is at C, AB = 13, and BC = 5. Point D lies on AB so that CD is perpendicular to AB. What is the length of CD?","choices":["60/13","5","13/2","6"],"answer":0,"solution":"The legs are BC = 5 and, by the Pythagorean theorem, AC = √(13² − 5²) = √144 = 12. The area equals ½·(leg)(leg) = ½(5)(12) = 30. Using AB as the base, area = ½·AB·CD = ½(13)(CD). Setting 30 = (13/2)·CD gives CD = 60/13 ≈ 4.62. (CD is the altitude to the hypotenuse = product of legs ÷ hypotenuse.)","shortcut":"Altitude to the hypotenuse = (leg·leg)/hypotenuse = (5·12)/13 = 60/13.","desmos":"Type (5*12)/13 → 4.615… = 60/13."},
];

